INSERT INTO lbn_admin (username, password, name) VALUES ('admin', 'admin123', 'Platform Administrator');
INSERT INTO lbn_user (id,username,password,display_name,party,leaning,gender,position,alma_mater,education_level,state,bio,interests,committee_id,avatar) VALUES
(1,'mcclellan','lbn123456','Mcclellan','Democrat','Conservative','Male','U.S. Senator from Arkansas','University of Arkansas','J.D.','Arkansas','John Little McClellan was a Democratic U.S. Senator from Arkansas (1943–1977) after serving in the U.S. House (1935–1943). A segregationist, he chaired the Senate Permanent Subcommittee on Investigations and later the Senate Government Operations Committee. He was influential in labor and internal security matters and opposed much civil rights legislation. He died in office in 1977.','Civil Rights & Society|Governance & Reform|Defense & Security',NULL,'/avatars/1.svg'),
(2,'ervin','lbn123456','Ervin','Democrat','Conservative','Male','U.S. Senator from North Carolina','University of North Carolina at Chapel Hill','J.D.','North Carolina','Samuel J. Ervin Jr. (1896–1985) was a Democratic U.S. senator from North Carolina (1954–1974). A lawyer and former North Carolina judge and legislator, he became a nationally known constitutional expert. Though initially a defender of segregation, he gained prominence for civil-liberties positions and for key roles in investigating Senator Joseph McCarthy and, most famously, chairing the Senate Watergate hearings that helped lead to President Nixon’s resignation.','Law & Justice|Environment & Energy|Civil Rights & Society',NULL,'/avatars/2.svg'),
(3,'hruska','lbn123456','Hruska','Republican','Conservative','Male','U.S. Senator from Nebraska','University of Nebraska–Lincoln','J.D.','Nebraska','Roman Lee Hruska was a Nebraska attorney and Republican politician who served as U.S. senator from Nebraska (1954–1976). He previously served as Douglas County attorney and as a U.S. Representative from Nebraska (1953–1954). In the Senate he was a prominent conservative voice, served in leadership roles including Senate Republican Whip, and was influential on judicial and law-enforcement issues.','Law & Justice',NULL,'/avatars/3.svg'),
(4,'claibornepell','lbn123456','Claiborne Pell','Democrat','Liberal','Male','U.S. Senator from Rhode Island','Princeton University; Columbia University','Master','Rhode Island','Claiborne Pell (1918–2009) was a Democratic U.S. Senator from Rhode Island, serving six terms from 1961 to 1997, the state’s longest-serving senator. He was a leading advocate for education and sponsored legislation that shaped the Basic Educational Opportunity Grant, later renamed the Pell Grant. He also worked on foreign relations and defense issues and authored books after leaving office.','Education & Science|Foreign Relations|Defense & Security',99,'/avatars/4.svg'),
(5,'humphrey','lbn123456','Humphrey','Democrat','Liberal','Male','U.S. Senator from Minnesota','University of Minnesota','Master','Minnesota','Hubert H. Humphrey (1911–1978) was a Minnesota Democrat who served as U.S. Senator (1949–1964; 1971–1978), mayor of Minneapolis (1945–1948), and U.S. Vice President under Lyndon B. Johnson (1965–1969). A leading liberal voice, he championed civil rights, social welfare, and arms control. He was the 1968 Democratic presidential nominee, losing to Richard Nixon.','Civil Rights & Society',NULL,'/avatars/5.svg'),
(6,'danielinouye','lbn123456','Daniel Inouye','Democrat','Unknown','Unknown','Unknown','Unknown','Unknown','','Information unavailable.','Governance & Reform',20,'/avatars/6.svg'),
(7,'bobpackwood','lbn123456','Bob Packwood','Republican','Moderate','Male','U.S. Senator from Oregon','Willamette University','J.D.','Oregon','Robert W. "Bob" Packwood (born 1932) is a retired lawyer and Republican politician from Oregon. He served in the Oregon House of Representatives (1963–1969) before representing Oregon in the U.S. Senate (1969–1995). In the Senate he was influential on tax and trade issues, chaired the Senate Finance Committee, and was active on environmental legislation. He resigned in 1995 amid sexual misconduct allegations.','Economics & Finance|Law & Justice|Environment & Energy',82,'/avatars/7.svg'),
(8,'bartlett','lbn123456','Bartlett','Republican','Conservative','Male','U.S. Representative from Maryland''s 6th district','University of Maryland, College Park','PhD','','Roscoe G. Bartlett Jr. (born 1926) was a Republican U.S. Representative from Maryland’s 6th district, serving from 1993 to 2013. A former scientist and engineer, he became known for work on energy policy and fiscal issues and later joined the House Tea Party Caucus. He was among the oldest members of the House at the end of his tenure.','Economics & Finance|Environment & Energy',NULL,'/avatars/8.svg'),
(9,'brock','lbn123456','Brock','Republican','Conservative','Male','U.S. Senator from Tennessee','Washington and Lee University','Bachelor','Tennessee','William E. Brock III (1930–2021) was a Republican politician from Tennessee. He served in the U.S. House (1963–1971) and the U.S. Senate (1971–1977). After leaving Congress, he chaired the Republican National Committee (1977–1981) and served in the Reagan administration as U.S. Trade Representative (1981–1985) and Secretary of Labor (1985–1987).','Economics & Finance|Civil Rights & Society|Governance & Reform',NULL,'/avatars/9.svg'),
(10,'curtis','lbn123456','Curtis','Republican','Moderate','Male','U.S. Senator from Utah','Brigham Young University','Bachelor','Utah','John Ream Curtis (born 1960) is a Utah Republican politician. He served as mayor of Provo (2010–2017) and then won a 2017 special election to represent Utah’s 3rd congressional district, serving in the U.S. House from 2017 to 2025. In 2024, he was elected to the U.S. Senate to succeed Mitt Romney and began serving as Utah’s junior senator in 2025.','Governance & Reform',NULL,'/avatars/10.svg'),
(11,'dominick','lbn123456','Dominick','Republican','Conservative','Male','U.S. Senator from Colorado','Yale University; University of Colorado Boulder','J.D.','Colorado','Peter H. Dominick was a Colorado attorney and Republican politician who served in the U.S. House of Representatives (1963–1967) and the U.S. Senate (1967–1975). A Yale graduate and University of Colorado Law alumnus, he focused on issues including government reform and foreign affairs. After leaving the Senate, he worked in banking and business and remained active in public and civic affairs.','Law & Justice|Governance & Reform|Economics & Finance',NULL,'/avatars/11.jpg'),
(12,'fannin','lbn123456','Fannin','Republican','Conservative','Male','U.S. Senator from Arizona','University of Arizona','Bachelor','Arizona','Paul J. Fannin was an Arizona businessman and Republican politician. He served as Governor of Arizona (1959–1965) and then as U.S. Senator from Arizona (1965–1977). In the Senate he supported Western development and defense-related issues. He retired in 1977 and remained active in business and civic affairs until his death in 2002.','Defense & Security',NULL,'/avatars/12.svg'),
(13,'fong','lbn123456','Fong','Republican','Conservative','Male','U.S. Senator from Hawaii','University of Hawaii','Bachelor','Hawaii','Hiram Leong Fong (1906–2004) was a Republican U.S. Senator from Hawaii (1959–1977) and the first Asian American elected to the U.S. Senate. Previously, he served in the Hawaii Territorial House (1938–1954) and Senate (1954–1959), including as Senate president. In the U.S. Senate he was known as a conservative on fiscal issues and was a candidate for president in 1964.','Economics & Finance',NULL,'/avatars/13.svg'),
(14,'goldwater','lbn123456','Goldwater','Republican','Conservative','Male','U.S. Senator from Arizona','University of Arizona','Bachelor','Arizona','Barry M. Goldwater (1909–1998) was a Republican U.S. Senator from Arizona (1953–1965; 1969–1987) and the GOP presidential nominee in 1964. A leading figure in modern American conservatism, he opposed much of the New Deal legacy and helped reshape the Republican Party’s conservative movement. He previously served on the Phoenix City Council and later was a major general in the Air Force Reserve.','Environment & Energy',NULL,'/avatars/14.svg'),
(15,'hansen','lbn123456','Hansen','Republican','Conservative','Male','U.S. Senator from Wyoming','University of Wyoming','J.D.','Wyoming','Clifford P. Hansen was a Republican U.S. Senator from Wyoming (1967–1979) and previously served as Governor of Wyoming (1963–1967). A University of Wyoming–trained attorney, he worked in ranching and law before entering state politics, including service in the Wyoming House. In the Senate he focused on western natural resources and public lands issues. He left the Senate in 1979.','Law & Justice|Environment & Energy|Education & Science',NULL,'/avatars/15.svg'),
(16,'stromthurmond','lbn123456','Strom Thurmond','Democrat (1954-1964), Republican (1964-2003)','Conservative','Male','U.S. Senator from South Carolina','Clemson Agricultural College; University of South Carolina','Bachelor','South Carolina','James Strom Thurmond Sr. was a longtime U.S. Senator from South Carolina (1954–2003) and previously served as governor (1947–1951). Elected to the Senate in 1954, he switched from the Democratic to the Republican Party in 1964. He ran for president in 1948 as the States’ Rights (Dixiecrat) candidate and was noted for a record-length filibuster against the Civil Rights Act of 1957.','Civil Rights & Society',53,'/avatars/16.svg'),
(17,'tower','lbn123456','Tower','Republican','Conservative','Male','U.S. Senator from Texas','Midwestern University (now Midwestern State University)','Master','Texas','John Goodwin Tower (1925–1991) was a Republican U.S. Senator from Texas, serving from 1961 to 1985 and becoming the first Texas Republican elected to the Senate since Reconstruction. A World War II Navy veteran, he later worked in broadcasting and academia before entering politics. After leaving the Senate, he chaired the Tower Commission investigating the Iran-Contra affair.','Defense & Security',NULL,'/avatars/17.svg'),
(18,'mcgovern','lbn123456','Mcgovern','Democrat','Liberal','Male','U.S. Senator from South Dakota','Dakota Wesleyan University; Northwestern University','PhD','South Dakota','George Stanley McGovern (1922–2012) was a Democrat who served as U.S. Senator from South Dakota (1963–1981) after terms in the U.S. House (1957–1961). A WWII bomber pilot and historian, he directed the Food for Peace program under President Kennedy. McGovern was the Democratic presidential nominee in 1972, running on an anti–Vietnam War platform and losing to Richard Nixon.','Defense & Security|Agriculture & Rural',NULL,'/avatars/18.svg'),
(19,'burdick','lbn123456','Burdick','Democrat','Liberal','Male','U.S. Senator from North Dakota','University of Minnesota','Bachelor','North Dakota','Quentin N. Burdick was a North Dakota Democrat who served in the U.S. House (1959–1960) and the U.S. Senate (1960–1992). Elected after the death of Senator William Langer, he won multiple reelections and became known for liberal positions and strong support for agriculture, energy, and Native American issues. He chaired the Senate Environment and Public Works Committee and died in office in 1992.','Environment & Energy|Agriculture & Rural',NULL,'/avatars/19.svg'),
(20,'randolph','lbn123456','Randolph','Democrat','Liberal','Male','U.S. Senator from West Virginia','Salem College','Bachelor','West Virginia','Jennings Randolph was a West Virginia Democrat who served in the U.S. House (1933–1947) and later the U.S. Senate (1958–1985). A long-tenured legislator, he worked on transportation and education issues and was known for supporting expanded voting rights, including efforts toward a constitutional amendment lowering the voting age. He retired in 1985 and was succeeded by Jay Rockefeller.','Law & Justice|Defense & Security|Education & Science',NULL,'/avatars/20.svg'),
(21,'case','lbn123456','Case','Republican','Moderate','Male','U.S. Senator from New Jersey','Rutgers University; Columbia University','J.D.','New Jersey','Clifford P. Case was a Republican U.S. Senator from New Jersey (1955–1979), after serving in the U.S. House (1945–1953). A prominent moderate, he supported civil rights, environmental protection, and government reform, and often broke with his party on social issues. He lost renomination in 1978 to Jeffrey Bell and died in 1982.','Governance & Reform|Environment & Energy|Civil Rights & Society',NULL,'/avatars/21.svg'),
(22,'cranston','lbn123456','Cranston','Democrat','Liberal','Male','U.S. Senator from California','Stanford University','Bachelor','California','Alan Cranston (1914–2000) was a Democratic U.S. Senator from California (1969–1993). A former journalist and California State Controller, he became a leading Senate liberal and served as Senate Democratic Whip (1977–1991). He ran for the 1984 Democratic presidential nomination advocating a nuclear freeze. In 1991 he was reprimanded for his role in the Keating Five savings-and-loan scandal.','Environment & Energy',NULL,'/avatars/22.svg'),
(23,'hart','lbn123456','Hart','Democrat','string','Male','U.S. Senator from Michigan','Georgetown University; University of Michigan Law School','J.D.','Michigan','Philip A. Hart was a Michigan Democrat who served as U.S. senator from 1959 until his death in 1976. A World War II Army veteran and former Michigan lieutenant governor, he became known as the "Conscience of the Senate" for his advocacy on civil rights, consumer protection, and immigration reform. The Hart Senate Office Building is named in his honor.','Defense & Security|Civil Rights & Society|Education & Science',NULL,'/avatars/23.svg'),
(24,'edwardkennedy','lbn123456','Edward Kennedy','Democrat','Liberal','Male','U.S. Senator from Massachusetts','Harvard University; University of Virginia School of Law','J.D.','Massachusetts','Edward M. "Ted" Kennedy (1932–2009) was a Democratic U.S. Senator from Massachusetts (1962–2009). A leading liberal voice, he chaired major committees and helped shape legislation on health care, education, immigration, civil rights, and labor, including the Americans with Disabilities Act and the Children’s Health Insurance Program. He sought the Democratic presidential nomination in 1980 and was a central figure in the Kennedy political family.','Medicine & Health|Civil Rights & Society|Defense & Security',46,'/avatars/24.jpg'),
(25,'montoya','lbn123456','Montoya','Democrat','Liberal','Male','U.S. Senator from New Mexico','University of Notre Dame','Bachelor','New Mexico','Joseph Manuel Montoya was a New Mexico Democrat who served as lieutenant governor (1947–1951; 1955–1957), then as a U.S. Representative (1957–1964). Appointed to the U.S. Senate in 1964 and later elected, he served as U.S. Senator from New Mexico from 1964 to 1977. He later lost renomination and left the Senate in 1977.','Governance & Reform',NULL,'/avatars/25.svg'),
(26,'moss','lbn123456','Moss','Democrat','Liberal','Male','U.S. Senator from Utah','University of Utah','J.D.','Utah','Frank E. "Ted" Moss was a Democratic U.S. Senator from Utah (1959–1977). A lawyer and former Salt Lake City commissioner, he chaired the Senate committee overseeing consumer and environmental health issues and advanced major consumer-protection legislation, including auto safety reforms. He lost reelection in 1976. Moss later worked in government relations and remained active in public affairs until his death in 2003.','Governance & Reform|Law & Justice|Medicine & Health',NULL,'/avatars/26.jpg'),
(27,'muskie','lbn123456','Muskie','Democrat','Liberal','Male','U.S. Senator from Maine','Bates College; Cornell University','J.D.','Maine','Edmund S. Muskie (1914–1996) was a Democratic U.S. Senator from Maine (1959–1980), previously serving as governor of Maine (1955–1959) and in the Maine House. A WWII Naval Reserve veteran and lawyer, he was the Democratic vice presidential nominee in 1968. He later served as U.S. Secretary of State under President Jimmy Carter (1980–1981).','Law & Justice|Defense & Security',NULL,'/avatars/27.jpg'),
(28,'percy','lbn123456','Percy','Republican','Moderate','Male','U.S. Senator from Illinois','University of Chicago; Northwestern University','J.D.','Illinois','Charles H. Percy (1919–2011) was a Republican U.S. Senator from Illinois (1967–1985) and previously an executive at Bell & Howell. In the Senate he was known as a moderate, served as chairman of the Senate Foreign Relations Committee (1977–1979), and worked on foreign policy and domestic issues. After losing reelection in 1984, he remained active in public policy and civic affairs.','Foreign Relations',NULL,'/avatars/28.svg'),
(29,'schweiker','lbn123456','Schweiker','Republican','Moderate','Male','U.S. Senator from Pennsylvania','Pennsylvania State University','Bachelor','Pennsylvania','Richard S. Schweiker (1926–2015) was a Republican U.S. Representative from Pennsylvania (1961–1969) and U.S. Senator from Pennsylvania (1969–1981). In the Senate he served on major committees and was known as a comparatively moderate Republican. He was Ronald Reagan’s 1976 primary running mate and later served as U.S. Secretary of Health and Human Services (1981–1983) under President Reagan.','Medicine & Health',NULL,'/avatars/29.svg'),
(30,'stafford','lbn123456','Stafford','Republican','Liberal','Male','U.S. Senator from Vermont','Middlebury College; University of Michigan Law School','J.D.','Vermont','Robert T. Stafford was a Vermont Republican who served in the U.S. House (1959–1961), as Vermont’s governor (1959–1961), and in the U.S. Senate (1971–1989). A liberal “Rockefeller Republican,” he was known for environmental protection and education policy, including major federal student aid legislation. After leaving the Senate, he remained influential in Vermont public life.','Education & Science|Environment & Energy',NULL,'/avatars/30.svg'),
(31,'tunney','lbn123456','Tunney','Democrat','Liberal','Male','U.S. Senator from California','Yale University; University of California, Berkeley; Harvard Law School','J.D.','California','John V. Tunney was a Democratic U.S. Senator from California (1971–1977). Son of boxer Gene Tunney, he previously served in the U.S. House (1965–1971). In the Senate he worked on consumer protection and criminal justice issues. After losing reelection to S. I. Hayakawa, he pursued law and business and later taught and wrote on public policy.','Law & Justice',NULL,'/avatars/31.svg'),
(32,'pearson','lbn123456','Pearson','Republican','Conservative','Male','U.S. Senator from Kansas','University of Kansas','J.D.','Kansas','James B. Pearson was a Republican U.S. Senator from Kansas (1962–1967), appointed to fill the vacancy after Andrew F. Schoeppel’s death and later elected to complete the term. A lawyer, he previously served as a Kansas district judge and was active in state Republican politics. He did not win reelection in 1966, losing the GOP primary to Bob Dole, and returned to legal and civic work.','Law & Justice',NULL,'/avatars/32.svg'),
(33,'bennett','lbn123456','Bennett','Republican','Conservative','Male','U.S. Senator from Utah','Brigham Young University, Harvard University','MBA','Utah','Robert Foster Bennett (1933–2016) was a Republican U.S. senator from Utah (1993–2011). A businessman and political operative, he previously served as president and CEO of the Franklin Institute. In the Senate he worked on banking, appropriations, rules, energy, and economic policy. A generally conservative lawmaker, he lost renomination in 2010 amid Tea Party opposition.','Economics & Finance|Law & Justice|Environment & Energy',NULL,'/avatars/33.svg'),
(34,'robertdole','lbn123456','Robert Dole','Republican','Conservative','Male','U.S. Senator from Kansas','University of Kansas','J.D.','Kansas','Robert J. "Bob" Dole (1923–2021) was a Republican U.S. Senator from Kansas (1969–1996) and previously a U.S. Representative (1961–1969). A decorated World War II Army veteran, he became a leading Senate Republican, serving as Minority and Majority Leader and chairing key committees. He was the 1976 Republican vice-presidential nominee and the 1996 Republican presidential nominee.','Defense & Security',12,'/avatars/34.svg'),
(35,'markhatfield','lbn123456','Mark Hatfield','Republican','Moderate','Male','U.S. Senator from Oregon','Stanford University; Willamette University','J.D.','Oregon','Mark Odom Hatfield (1922–2011) was a Republican U.S. senator from Oregon (1967–1997) and previously served in the U.S. Navy, the Oregon House, and as Oregon secretary of state and governor. A prominent moderate, he was an early opponent of the Vietnam War and a leading appropriator, chairing the Senate Appropriations Committee and advocating arms control and domestic spending priorities.','Defense & Security|Economics & Finance',32,'/avatars/35.jpg'),
(36,'javits','lbn123456','Javits','Republican','Liberal','Male','U.S. Senator from New York','New York University School of Law','J.D.','New York','Jacob K. Javits was a New York Republican who served in the U.S. House (1947–1954) and U.S. Senate (1957–1981), and as New York Attorney General (1955–1957). A leading liberal Republican, he backed labor, civil rights, and many Great Society initiatives, and became an early critic of the Vietnam War. He helped draft the 1973 War Powers Resolution.','Defense & Security|Civil Rights & Society|Law & Justice',NULL,'/avatars/36.svg'),
(37,'mansfield','lbn123456','Mansfield','Democrat','Liberal','Male','U.S. Senator from Montana','University of Montana','Master','Montana','Mike Mansfield (1903–2001) was a Montana Democrat who served in the U.S. House (1943–1953) and U.S. Senate (1953–1977). He became Senate Majority Leader in 1961, leading Democrats for 16 years and guiding major Great Society legislation. After leaving the Senate, he served as U.S. Ambassador to Japan (1977–1988).','Foreign Relations',NULL,'/avatars/37.svg'),
(38,'jackson','lbn123456','Jackson','Democrat','Liberal','Male','U.S. Senator from Washington','Stanford University; University of Washington','J.D.','Washington','Henry M. "Scoop" Jackson was a U.S. Senator from Washington (1953–1983), after serving in the U.S. House (1941–1953). A Cold War Democrat, he was influential on defense and foreign policy and chaired major committees, including Interior and Insular Affairs and Governmental Affairs. He ran for the Democratic presidential nomination in 1972 and 1976. He died in office in 1983.','Defense & Security|Foreign Relations|Governance & Reform',NULL,'/avatars/38.svg'),
(39,'abourezk','lbn123456','Abourezk','Democrat','Liberal','Male','U.S. Senator from South Dakota','University of South Dakota','J.D.','South Dakota','James G. Abourezk (1931–2023) was a South Dakota Democratic politician and attorney. He served one term in the U.S. House (1971–1973) and one term in the U.S. Senate (1973–1979), becoming the first Arab American U.S. senator. After leaving Congress he founded the American-Arab Anti-Discrimination Committee (1980) and was active on civil rights and Middle East policy issues.','Law & Justice|Civil Rights & Society',NULL,'/avatars/39.jpg'),
(40,'church','lbn123456','Church','Democrat','Liberal','Male','U.S. Senator from Idaho','Stanford University','Bachelor','Idaho','Frank Church was a U.S. Senator from Idaho (1957–1981). A Democrat, he became a leading voice on foreign policy, opposing the Vietnam War and sponsoring major environmental legislation including the Wilderness Act. He chaired the Senate Select Committee to Study Governmental Operations with Respect to Intelligence Activities (“Church Committee”), which investigated U.S. intelligence agencies in the 1970s. He lost reelection in 1980.','Defense & Security|Environment & Energy|Foreign Relations',NULL,'/avatars/40.svg'),
(41,'petedomenici','lbn123456','Pete Domenici','Republican','Conservative','Male','U.S. Senator from New Mexico','University of New Mexico','Bachelor','New Mexico','Pete Domenici was a Republican U.S. Senator from New Mexico (1973–2009), the state’s longest-serving senator. He previously served on the Albuquerque City Commission and practiced law. In the Senate he chaired the Budget Committee and the Energy and Natural Resources Committee, becoming a leading figure on federal budgeting, energy policy, and western water issues. He retired in 2009 and was succeeded by Tom Udall.','Environment & Energy|Economics & Finance|Law & Justice',36,'/avatars/41.svg'),
(42,'haskell','lbn123456','Haskell','Democrat','string','Male','string','Unknown','Unknown','','Unknown','Governance & Reform',NULL,'/avatars/42.svg'),
(43,'mcclure','lbn123456','Mcclure','Republican','Conservative','Male','U.S. Senator from Idaho','University of Idaho','J.D.','Idaho','James A. McClure was a Republican U.S. Senator from Idaho (1973–1993) and previously served in the U.S. House (1967–1973). A lawyer, he became a leading conservative voice on energy and natural-resources policy and chaired the Senate Energy and Natural Resources Committee. After leaving Congress, he worked in government relations and policy advocacy.','Environment & Energy|Law & Justice|Foreign Relations',NULL,'/avatars/43.svg'),
(44,'howardmetzenbaum','lbn123456','Howard Metzenbaum','Democrat','Liberal','Male','U.S. Senator from Ohio','Ohio State University','Unknown','Ohio','Howard Morton Metzenbaum was a Democratic U.S. Senator from Ohio, first appointed in 1974 and then elected in 1976, serving until 1995. He previously served in the Ohio House and Senate (1943–1951) and was a businessman. In the Senate he was known as a liberal, pro-consumer advocate and served on major committees including Judiciary.','Law & Justice|Defense & Security',93,'/avatars/44.svg'),
(45,'earlnelson','lbn123456','Earl Nelson','Democrat','Moderate','Male','U.S. Senator from Wisconsin','San Jose State University; University of Wisconsin–Madison','PhD','Wisconsin','Gaylord Nelson was a Democratic U.S. Senator from Wisconsin (1963–1981) and previously served as Wisconsin’s governor (1959–1963). In the Senate he was a leading environmental advocate and is best known as the founder of Earth Day (first held in 1970). After leaving office, he worked with the Wilderness Society and remained active in conservation issues.','Environment & Energy',160,'/avatars/45.jpg'),
(46,'eagleton','lbn123456','Eagleton','Democrat','Liberal','Male','U.S. Senator from Missouri','Amherst College; Harvard Law School','J.D.','Missouri','Thomas F. Eagleton was a Democratic U.S. Senator from Missouri (1968–1987). Previously he served as Missouri attorney general (1961–1965) and lieutenant governor (1965–1969). In 1972 he was the Democratic nominee for vice president with George McGovern but withdrew from the ticket. In the Senate he was known for liberal positions, including opposition to the Vietnam War.','Law & Justice|Defense & Security',NULL,'/avatars/46.svg'),
(47,'mcintyre','lbn123456','Mcintyre','Democrat','Conservative','Male','U.S. Representative from North Carolina''s 7th district','University of North Carolina at Chapel Hill','Bachelor','','Charles R. "Charlie" McIntyre (born 1942) is an American politician and attorney. A conservative Democrat, he served in the U.S. House of Representatives for North Carolina''s 7th district from 1997 to 2015, after earlier service in the North Carolina Senate (1973–1978). In Congress he was associated with the Blue Dog Coalition and represented the Wilmington area.','Law & Justice',NULL,'/avatars/47.svg'),
(48,'brooke','lbn123456','Brooke','Republican','Moderate','Male','U.S. Senator from Massachusetts','Howard University; Boston University School of Law','J.D.','Massachusetts','Edward W. Brooke III was a Massachusetts Republican who served as U.S. senator from 1967 to 1979. A World War II Army veteran and lawyer, he was Massachusetts attorney general (1963–1967). Brooke was the first African American elected to the U.S. Senate by popular vote and the first to be re-elected. He later served on corporate and public commissions after leaving the Senate.','Defense & Security|Law & Justice',NULL,'/avatars/48.svg'),
(49,'tomcotton','lbn123456','Tom Cotton','Republican','Conservative','Male','U.S. Senator from Arkansas','Harvard University; Harvard Law School','J.D.','Arkansas','Thomas Bryant Cotton is a Republican U.S. senator from Arkansas, serving since 2015. A former U.S. Army infantry officer and Iraq and Afghanistan veteran, he previously represented Arkansas’s 4th congressional district in the U.S. House (2013–2015). Elected to the Senate in 2014, he has been a leading hawkish voice on national security and foreign policy and has chaired major Senate Republican and intelligence roles.','Defense & Security|Foreign Relations',268,'/avatars/49.jpg'),
(50,'hathaway','lbn123456','Hathaway','Democrat','Liberal','Male','U.S. Senator from Maine','Bates College; Harvard Law School','J.D.','Maine','William D. Hathaway was a Maine lawyer and Democrat who served in the U.S. House representing Maine’s 2nd district (1965–1973) and then as U.S. Senator from Maine (1973–1979). He later served as a commissioner of the Federal Maritime Commission (1990–1999).','Law & Justice',NULL,'/avatars/50.svg'),
(51,'hughes','lbn123456','Hughes','Democrat','Liberal','Male','U.S. Senator from New Jersey','Syracuse University','J.D.','New Jersey','Harold E. Hughes was a U.S. Senator from Iowa (1969–1975) and a Democrat. A former truck driver and recovering alcoholic, he served as Iowa’s governor (1963–1969) and gained national attention for anti-poverty and civil rights advocacy. In the Senate he focused on labor, health, and social welfare issues, then later served in federal alcoholism and substance-abuse policy roles.','Civil Rights & Society|Medicine & Health',NULL,'/avatars/51.svg'),
(52,'mondale','lbn123456','Mondale','Democrat','Liberal','Male','U.S. Senator from Minnesota','University of Minnesota','J.D.','Minnesota','Walter F. "Fritz" Mondale was a Democratic U.S. Senator from Minnesota (1964–1976), appointed after Hubert Humphrey became vice president and later elected. Previously he served as Minnesota attorney general (1960–1964). Mondale was vice president of the United States under Jimmy Carter (1977–1981) and the Democratic presidential nominee in 1984.','Law & Justice',NULL,'/avatars/52.jpg'),
(53,'pastore','lbn123456','Pastore','Democrat','Liberal','Male','U.S. Senator from Rhode Island','Northeastern University; Boston University School of Law','J.D.','Rhode Island','John O. Pastore (1907–2000) was a Rhode Island Democrat who served as governor (1945–1950) and U.S. senator (1950–1976). Trained as a lawyer, he was the first Italian American elected to the U.S. Senate. In the Senate he chaired major committees, including Appropriations, and played a prominent role in federal science, health, and education policy oversight.','Education & Science|Law & Justice|Medicine & Health',NULL,'/avatars/53.svg'),
(54,'proxmire','lbn123456','Proxmire','Democrat','string','Male','U.S. Senator from Wisconsin','Yale University','Bachelor','Wisconsin','Edward William Proxmire (1915–2005) was a Democratic U.S. Senator from Wisconsin, serving from 1957 to 1989. A noted fiscal watchdog, he created the satirical Golden Fleece Award to highlight what he viewed as wasteful federal spending. He served on the Senate Appropriations Committee, Senate Banking Committee, and the Joint Economic Committee, where he scrutinized military and other government programs.','Economics & Finance|Defense & Security|Governance & Reform',NULL,'/avatars/54.svg'),
(55,'ribicoff','lbn123456','Ribicoff','Democrat','Liberal','Male','U.S. Senator from Connecticut','University of Connecticut, University of Chicago','J.D.','Connecticut','Abraham A. Ribicoff (1910–1998) was a Connecticut Democrat who served in the U.S. House (1949–1961), as governor of Connecticut (1955–1961), U.S. Secretary of Health, Education, and Welfare (1961–1962), and U.S. Senator from Connecticut (1963–1981). He gained national prominence on domestic policy and urban issues, and later worked in private law and consulting.','Law & Justice|Medicine & Health|Education & Science',NULL,'/avatars/55.svg'),
(56,'weicker','lbn123456','Weicker','Republican (1969-1989), Independent (after 1989)','Moderate','Male','U.S. Senator from Connecticut','Yale University; University of Virginia School of Law','J.D.','Connecticut','Lowell P. Weicker Jr. served as a U.S. Representative from Connecticut (1969–1971) and U.S. Senator from Connecticut (1971–1989) as a Republican. A liberal “Rockefeller Republican,” he criticized President Nixon during Watergate and ran for the 1980 Republican presidential nomination. He lost reelection in 1988 to Joe Lieberman. Weicker later left the GOP and was elected governor of Connecticut (1991–1995) on A Connecticut Party ticket.','Environment & Energy',NULL,'/avatars/56.svg'),
(57,'williams','lbn123456','Williams','Democrat','Liberal','Male','U.S. Senator from New Jersey','Oberlin College; University of Denver','J.D.','New Jersey','Harrison A. "Pete" Williams Jr. (1919–2003) was a Democratic U.S. Senator from New Jersey (1959–1982). He previously served in the U.S. House (1953–1957) and in the New Jersey Senate. In the Senate he chaired the Labor and Human Resources Committee and was a leading liberal voice on labor and education. He resigned after being convicted in the FBI ABSCAM corruption investigation.','Civil Rights & Society|Education & Science|Governance & Reform',NULL,'/avatars/57.svg'),
(58,'hartke','lbn123456','Hartke','Democrat','Liberal','Male','U.S. Senator from Indiana','Indiana University','J.D.','Indiana','Rupert Vance Hartke (1919–2003) was a Democratic politician from Indiana. He served as mayor of Evansville before winning election to the U.S. Senate, serving from 1959 to 1977. In the Senate he supported Great Society programs and became a prominent critic of the Vietnam War. He briefly sought the 1972 Democratic presidential nomination and lost reelection in 1976 to Richard Lugar.','Defense & Security',NULL,'/avatars/58.svg'),
(59,'metcalf','lbn123456','Metcalf','Democrat','Liberal','Male','U.S. Senator from Montana','Montana State University, University of Montana','J.D.','Montana','Lee W. Metcalf was a Montana Democrat who served in the U.S. House (1953–1961) and U.S. Senate (1961–1978). Born in Stevensville, Montana, he was a lawyer and former state judge. In the Senate he became known for environmental and public-lands advocacy and served as the Senate’s permanent acting president pro tempore (1963–1978) until his death in office.','Law & Justice|Environment & Energy',NULL,'/avatars/59.svg'),
(60,'cannon','lbn123456','Cannon','Democrat','Moderate','Male','U.S. Senator from Nevada','Northern Arizona University; University of Arizona','J.D.','Nevada','Howard W. Cannon was a Democratic U.S. Senator from Nevada (1959–1983). Born in St. George, Utah, he earned degrees from Northern Arizona University and a J.D. from the University of Arizona. He served in the U.S. Army and Army Air Corps during World War II, later reaching major general in the Air Force Reserve. Cannon also served as city attorney for Las Vegas before the Senate.','Defense & Security|Education & Science|Law & Justice',NULL,'/avatars/60.jpg'),
(61,'taft','lbn123456','Taft','Republican','Conservative','Male','U.S. Senator from Ohio','Yale University; Harvard University','J.D.','Ohio','Robert A. Taft (1889–1953) was a Republican U.S. Senator from Ohio (1939–1953) and a leading figure in the conservative coalition. Known as “Mr. Republican,” he opposed much of the New Deal’s expansion and emphasized limited government. He co-sponsored the Taft–Hartley Act of 1947. Son of President William Howard Taft, he was a Cincinnati lawyer and briefly served as Senate majority leader in 1953.','Law & Justice|Defense & Security|Governance & Reform',NULL,'/avatars/61.svg'),
(62,'evanbayh','lbn123456','Evan Bayh','Democrat','Moderate','Male','U.S. Senator from Indiana','Indiana University Bloomington; University of Virginia','J.D.','Indiana','Birch Evans “Evan” Bayh III (born 1955) is an Indiana Democrat. He served as Indiana secretary of state (1987–1989), then as the state’s 46th governor (1989–1997). Bayh was elected to the U.S. Senate from Indiana in 1998 and served from 1999 to 2011, leaving after announcing he would not seek reelection in 2010.','Governance & Reform',155,'/avatars/62.jpg'),
(63,'baker','lbn123456','Baker','Republican','Conservative','Male','U.S. Senator from Tennessee','University of Tennessee; University of Cincinnati College of Law','J.D.','Tennessee','Howard Henry Baker Jr. was a Republican U.S. Senator from Tennessee (1967–1985), serving as Senate Minority Leader (1981–1985) and Majority Leader (1980–1981). A prominent figure during the Watergate era, he was known for a pragmatic, bipartisan style. After leaving the Senate he served as White House Chief of Staff under President Ronald Reagan (1987–1988) and later as U.S. Ambassador to Japan (2001–2005).','Defense & Security|Environment & Energy|Foreign Relations',NULL,'/avatars/63.svg'),
(64,'bible','lbn123456','Bible','Democrat','Moderate','Male','U.S. Senator from Nevada','Georgetown University','Bachelor','Nevada','Alan Bible was a Nevada Democrat who served as a U.S. Senator from 1954 to 1974, after serving as a U.S. Representative (1949–1954). A World War II Navy veteran, he became a key appropriations and public works legislator and supported major federal investments in Nevada, including water and infrastructure projects. He chaired the Senate Committee on Public Works (later Environment and Public Works).','Defense & Security|Environment & Energy|Economics & Finance',NULL,'/avatars/64.jpg'),
(65,'chiles','lbn123456','Chiles','Democrat','Moderate','Male','U.S. Senator from Florida','University of Florida','J.D.','Florida','Lawton Chiles (1930–1998) was a Florida Democrat who served in the U.S. Senate from 1971 to 1989. A Korean War veteran and University of Florida law graduate, he previously served in the Florida House and Florida Senate. Known as “Walkin’ Lawton” for his 1970 campaign walk across Florida, he later became the 41st governor of Florida (1991–1998), serving until his death.','Law & Justice|Defense & Security|Education & Science',NULL,'/avatars/65.svg'),
(66,'clark','lbn123456','Clark','Democrat','Liberal','Male','U.S. Senator from Iowa','Grinnell College; University of Chicago','PhD','Iowa','John Culver "Chet" Culver Clark was a Democratic U.S. Senator from Iowa (1973–1979), elected in 1972 after serving as U.S. Representative from Iowa (1965–1973). A former U.S. Navy officer, he later worked in education and public policy. He was defeated for reelection to the Senate in 1978.','Defense & Security|Education & Science',NULL,'/avatars/66.svg'),
(67,'cook','lbn123456','Cook','Republican','Conservative','Male','U.S. Senator from Kentucky','University of Kentucky','Bachelor','Kentucky','Marlow W. Cook was a Republican U.S. Senator from Kentucky (1968–1974). He previously served in the U.S. House representing Kentucky (1957–1963) and as county judge/executive in Louisville–Jefferson County. In the Senate he was known as a moderate-to-liberal Republican and supported civil rights. He later switched to the Democratic Party after leaving office.','Law & Justice|Civil Rights & Society',NULL,'/avatars/67.svg'),
(68,'gravel','lbn123456','Gravel','Democrat','Progressive','Male','U.S. Senator from Alaska','Columbia University','Bachelor','Alaska','Maurice Robert “Mike” Gravel (1930–2021) was a Democratic U.S. Senator from Alaska (1969–1981). Previously he served in the Alaska House of Representatives and was Speaker. In the Senate he gained national attention for efforts to end the Vietnam-era draft and for entering the Pentagon Papers into the congressional record in 1971. He later ran for president in 2008 and 2020.','Governance & Reform',NULL,'/avatars/68.svg'),
(69,'scottpa','lbn123456','Scott (Pa.)','Republican','Conservative','Male','U.S. Senator from Pennsylvania','Georgetown University; Georgetown University Law Center','J.D.','Pennsylvania','Hugh Scott (1900–1994) was a Republican U.S. Senator from Pennsylvania (1959–1977) and earlier served in the U.S. House from Pennsylvania (1941–1945, 1947–1959). A former lawyer and Army veteran, he became Senate Minority Whip (1969–1973) and Senate Minority Leader (1973–1977). Scott was a prominent GOP figure during the Nixon and Ford years.','Defense & Security|Law & Justice',NULL,'/avatars/69.svg'),
(70,'stevenson','lbn123456','Stevenson','Democrat','Liberal','Male','U.S. Senator from Illinois','Princeton University; Harvard Law School','J.D.','Illinois','Adlai E. Stevenson III was a Democratic U.S. Senator from Illinois (1970–1981). A member of the prominent Stevenson political family, he earlier served as Illinois state treasurer (1965–1967). In the Senate he focused on government oversight and foreign policy issues. After leaving office, he practiced law and remained active in Illinois and national public affairs.','Governance & Reform|Law & Justice|Foreign Relations',NULL,'/avatars/70.svg'),
(71,'mathias','lbn123456','Mathias','Republican','string','Male','U.S. Senator from Maryland','Haverford College; University of Maryland School of Law','J.D.','Maryland','Charles McCurdy "Mac" Mathias Jr. (1922–2010) was a Republican U.S. Senator from Maryland (1969–1987), previously serving as a U.S. Representative (1961–1969). A moderate-to-liberal Republican, he was noted for support of civil rights, environmental protection, and arms control. He served in the U.S. Navy during World War II and practiced law before entering politics.','Defense & Security|Law & Justice|Environment & Energy',NULL,'/avatars/71.svg'),
(72,'magnuson','lbn123456','Magnuson','Democrat','Liberal','Male','U.S. Senator from Washington','University of Washington','J.D.','Washington','Warren G. Magnuson was a Democratic politician from Washington. He served in the U.S. House (1937–1944) and then the U.S. Senate (1944–1981), becoming Washington’s longest-serving senator. A major committee chairman, he shaped consumer protection, health, and commerce policy and served as Senate president pro tempore near the end of his tenure. He was defeated for reelection in 1980.','Medicine & Health|Defense & Security|Economics & Finance',NULL,'/avatars/72.svg'),
(73,'jjohnston','lbn123456','J. Johnston','Democrat','Conservative','Male','U.S. Senator from Virginia','Washington College (now Washington and Lee University)','Bachelor','Virginia','John Warfield Johnston was a Virginia lawyer and Democratic politician. A former Confederate, he served in the Virginia State Senate and was later elected to the U.S. Senate after Virginia’s readmission following the Civil War, serving 1870–1883. Initially barred under the Fourteenth Amendment, he was eventually seated and became one of the first former Confederates to serve in the U.S. Senate.','Defense & Security|Law & Justice',22,'/avatars/73.svg'),
(74,'tedstevens','lbn123456','Ted Stevens','Republican','Conservative','Male','U.S. Senator from Alaska','UCLA','Bachelor','Alaska','Ted Stevens was a Republican U.S. Senator from Alaska (1968–2009) and longtime Senate appropriator. A World War II Army Air Forces veteran, he served as Alaska’s solicitor and later as a federal prosecutor before appointment to the Senate. Stevens became Senate President pro tempore (2007–2009) and chaired the Appropriations Committee, wielding major influence over federal spending for Alaska.','Defense & Security|Law & Justice|Economics & Finance',33,'/avatars/74.svg'),
(75,'gurney','lbn123456','Gurney','Republican','Conservative','Male','U.S. Senator from Florida','Unknown','J.D.','Florida','Edward J. Gurney Jr. (1914–1996) was a Republican attorney and U.S. Army officer. He served in the U.S. House representing Florida from 1963 to 1969, then as U.S. Senator from Florida from 1969 to 1974, the first Florida Republican elected to the Senate since Reconstruction. Indicted in an influence-peddling scandal, he resigned in 1974 and was later acquitted.','Defense & Security|Law & Justice',NULL,'/avatars/75.svg'),
(76,'ernesthollings','lbn123456','Ernest Hollings','Democrat','string','Male','U.S. Senator from South Carolina','The Citadel; University of South Carolina School of Law','J.D.','South Carolina','Ernest Frederick “Fritz” Hollings (1922–2019) was a South Carolina Democrat. He served in the South Carolina House (1949–1954), as lieutenant governor (1955–1959), and as governor (1959–1963). Hollings was elected to the U.S. Senate in 1966 and served from 1966 to 2005, becoming one of South Carolina’s longest-serving senators and working for decades alongside Strom Thurmond.','Governance & Reform',21,'/avatars/76.jpg'),
(77,'beall','lbn123456','Beall','Republican','Conservative','Male','U.S. Senator from Maryland','Yale University','Bachelor','Maryland','John Glenn Beall Jr. (1927–2006) was a Maryland Republican politician and businessman. He served in the Maryland House of Delegates (1962–1968), the U.S. House of Representatives (1969–1971), and the U.S. Senate (1971–1977). He was the son of Senator J. Glenn Beall and later worked in business after leaving Congress.','Governance & Reform',NULL,'/avatars/77.svg'),
(78,'long','lbn123456','Long','Democrat','Conservative','Male','U.S. Senator from Louisiana','University of Oklahoma','J.D.','Louisiana','Russell B. Long was a Democratic U.S. Senator from Louisiana (1948–1987), succeeding his father, Huey Long. A powerful conservative Democrat, he chaired the Senate Finance Committee (1966–1981), shaping major tax, trade, Social Security, and welfare legislation. Earlier he served as a Navy officer in World War II and worked as a lawyer. After retiring, he remained influential in Louisiana politics.','Defense & Security|Economics & Finance|Law & Justice',NULL,'/avatars/78.svg'),
(79,'williamroth','lbn123456','William Roth','Republican','Conservative','Male','U.S. Senator from Delaware','University of Oregon; Harvard University','J.D.','Delaware','William V. Roth Jr. (1921–2003) was a Republican U.S. Senator from Delaware (1971–2001). A World War II veteran, he also served in the U.S. House (1967–1971). Roth became best known for sponsoring the Economic Recovery Tax Act of 1981, creating the Roth IRA concept. After leaving the Senate, he served as U.S. Ambassador to the Netherlands (2001–2003).','Defense & Security|Law & Justice|Economics & Finance',72,'/avatars/79.jpg'),
(80,'mcgee','lbn123456','Mcgee','Democrat','Moderate','Male','U.S. Senator from Wyoming','University of Wyoming','J.D.','Wyoming','Gale W. McGee was a Wyoming Democrat who served as a U.S. Senator (1959–1977). A former history professor and diplomat, he became a leading advocate for public power, space and science policy, and government reform. After leaving the Senate, he served as U.S. Ambassador to the Organization of American States (1977–1981).','Education & Science|Governance & Reform|Foreign Relations',NULL,'/avatars/80.svg'),
(81,'robertbyrd','lbn123456','Robert Byrd','Democrat','Conservative','Male','U.S. Senator from West Virginia','West Virginia University; American University','J.D.','West Virginia','Robert C. Byrd (1917–2010) was a Democratic U.S. senator from West Virginia (1959–2010) and previously a U.S. representative (1953–1959). He served over 51 years in the Senate, the longest tenure of any U.S. senator. Byrd held major leadership roles including Senate Majority Leader, Senate Minority Leader, and President pro tempore, and was a powerful appropriations advocate for West Virginia.','Economics & Finance',19,'/avatars/81.jpg'),
(82,'huddleston','lbn123456','Huddleston','Democrat','string','Male','U.S. Senator from Kentucky','University of Kentucky','Bachelor','Kentucky','Walter Dee "Dee" Huddleston (1926–2018) was a Kentucky broadcaster and Democratic politician. He served in the Kentucky Senate (1966–1972) before being elected U.S. Senator from Kentucky, serving two terms (1973–1985). He lost his 1984 re-election bid to Mitch McConnell by a narrow margin.','Governance & Reform',NULL,'/avatars/82.svg'),
(83,'georgeallen','lbn123456','George Allen','Democrat','Conservative','Male','U.S. Senator from Alabama','Birmingham–Southern College; University of Virginia School of Law','J.D.','Alabama','James “Jim” Allen was a conservative Democratic U.S. Senator from Alabama (1969–1979). Previously he served as Alabama’s lieutenant governor (1963–1967) and as a judge on the Alabama circuit court. In the Senate he was known for states’ rights positions and opposition to many liberal initiatives. He died in office in 1979.','Law & Justice',168,'/avatars/83.svg'),
(84,'talmadge','lbn123456','Talmadge','Democrat','Conservative','Male','U.S. Senator from Georgia','University of Georgia','Bachelor','Georgia','Herman Eugene Talmadge (1913–2002) was a Georgia Democrat who served as governor (1947; 1948–1955) and U.S. senator (1957–1981). Initially a prominent segregationist and opponent of civil rights, he later moderated some positions as Southern politics changed. In the Senate he became a leading voice on agriculture and chaired the Senate Agriculture Committee. He lost reelection in 1980 amid ethics and financial controversies.','Agriculture & Rural|Civil Rights & Society|Governance & Reform',NULL,'/avatars/84.svg'),
(85,'eastland','lbn123456','Eastland','Democrat','Conservative','Male','U.S. Senator from Mississippi','University of Mississippi; Vanderbilt University; University of Alabama','J.D.','Mississippi','James Oliver Eastland was a Mississippi attorney, plantation owner, and Democratic U.S. senator (1941; 1943–1978). A leading segregationist, he was a prominent opponent of civil rights legislation and a key voice for Southern resistance to racial integration. Eastland chaired the Senate Judiciary Committee for years and wielded substantial influence over judicial nominations and civil rights policy before resigning in 1978.','Civil Rights & Society|Law & Justice',NULL,'/avatars/85.svg'),
(86,'scottva','lbn123456','Scott (Va.)','Republican','Conservative','Male','U.S. Representative from Virginia''s 4th district','Virginia Polytechnic Institute and State University (Virginia Tech), University of Richmond School of Law','J.D.','Virginia who served in the U','Robert Cortez "Bobby" Scott is a Republican politician from Virginia who served in the U.S. House of Representatives for Virginia''s 4th district (1973–1975). A lawyer and businessman, he later served in the Virginia Senate (1978–1995). He won election to Congress in 1972 and was succeeded after one term.','Law & Justice',NULL,'/avatars/86.svg'),
(87,'sparkman','lbn123456','Sparkman','Democrat','Moderate','Male','U.S. Senator from Alabama','University of Alabama','LL.B.','Alabama','John J. Sparkman was a Democratic U.S. Senator from Alabama (1946–1979) and previously a U.S. Representative (1937–1946). He was a long-serving Senate leader and chaired the Senate Foreign Relations Committee. Sparkman was the Democratic nominee for vice president in 1952, running with Adlai Stevenson. He retired in 1979.','Foreign Relations',NULL,'/avatars/87.svg'),
(88,'bellmon','lbn123456','Bellmon','Republican','Conservative','Male','U.S. Senator from Oklahoma','Oklahoma State University','Bachelor','Oklahoma','Henry Louis Bellmon was an Oklahoma Republican politician. After serving in the Oklahoma House of Representatives, he became the first Republican governor of Oklahoma (1963–1967). He later served as a U.S. Senator from Oklahoma (1969–1981). Bellmon returned as governor (1987–1991), emphasizing education reform. A World War II veteran, he later struggled with Parkinson’s disease and died in 2009.','Defense & Security|Medicine & Health|Education & Science',NULL,'/avatars/88.svg'),
(89,'fulbright','lbn123456','Fulbright','Democrat','Liberal','Male','U.S. Senator from Arkansas','University of Arkansas; George Washington University; Pembroke College, Oxford','J.D.','Arkansas','J. William Fulbright (1905–1995) was a Democratic U.S. Senator from Arkansas (1945–1974) and longtime chair of the Senate Foreign Relations Committee. Earlier he served in the U.S. House and was president of the University of Arkansas. A leading internationalist, he created the Fulbright Program and became a prominent critic of U.S. involvement in the Vietnam War.','Foreign Relations|Defense & Security|Education & Science',NULL,'/avatars/89.svg'),
(90,'griffin','lbn123456','Griffin','Republican','Conservative','Male','U.S. Senator from Michigan','Central Michigan University; Michigan State University','J.D.','Michigan','Robert P. Griffin was a Michigan politician who served in the U.S. House (1967–1969) and was appointed to the U.S. Senate (1966–1969) after Pat McNamara’s death, losing the 1968 election. Earlier he served in the Michigan Senate. After Congress he worked in Washington, D.C., including as a legal and government affairs executive.','Law & Justice|Governance & Reform',NULL,'/avatars/90.svg'),
(91,'josephbiden','lbn123456','Joseph Biden','Democrat','Liberal','Male','U.S. Senator from Delaware','University of Delaware; Syracuse University College of Law','J.D.','Delaware','Joseph R. Biden Jr. served as a Democratic U.S. senator from Delaware (1973–2009), chairing the Senate Judiciary and Foreign Relations committees and playing leading roles on crime and violence-against-women legislation and Supreme Court hearings. He was vice president of the United States (2009–2017) under Barack Obama and later served as the 46th U.S. president (2021–2025).','Law & Justice|Defense & Security|Foreign Relations',100,'/avatars/91.svg'),
(92,'toddyoung','lbn123456','Todd Young','Republican','Conservative','Male','U.S. Senator from Alaska','Unknown','Unknown','Alaska','Don Young was a Republican U.S. Representative from Alaska’s at-large district, serving from 1973 to 2022, and was the longest-serving House Republican. He previously served in the Alaska House and Senate and as mayor of Fort Yukon. Known as a strong advocate for Alaska development and infrastructure, he chaired the House Natural Resources Committee and served on Transportation and Infrastructure.','Environment & Energy',282,'/avatars/92.jpg'),
(93,'aiken','lbn123456','Aiken','Republican','Moderate','Male','U.S. Senator from Vermont','University of Vermont','Bachelor','Vermont','George David Aiken was a Vermont Republican who served as governor (1937–1941) and U.S. senator (1941–1975). A horticulturist and former state legislator, he became a senior Northeastern Republican voice, backing measures such as the Full Employment Act of 1946 and early food assistance legislation. He supported postwar international programs like the Truman Doctrine and Marshall Plan.','Defense & Security|Foreign Relations|Agriculture & Rural',NULL,'/avatars/93.svg'),
(94,'lloydbentsen','lbn123456','Lloyd Bentsen','Democrat','Moderate','Male','U.S. Senator from Texas','University of Texas at Austin','J.D.','Texas','Lloyd M. Bentsen Jr. (1921–2006) was a Texas Democrat who served in the U.S. House (1948–1955) and U.S. Senate (1971–1993). A World War II Army Air Forces veteran awarded the Distinguished Flying Cross, he chaired the Senate Finance Committee (1987–1993). He was the 1988 Democratic vice-presidential nominee and later served as U.S. secretary of the treasury (1993–1994).','Defense & Security|Economics & Finance',78,'/avatars/94.svg'),
(95,'jessehelms','lbn123456','Jesse Helms','Republican','Conservative','Male','U.S. Senator from North Carolina','Wake Forest College; Yale University','Bachelor','North Carolina','Jesse Alexander Helms Jr. (1921–2008) was a Republican U.S. Senator from North Carolina (1973–2003). A former Raleigh newspaper editor and WRAL-TV commentator, he became a leading conservative voice on foreign policy and social issues. Helms chaired the Senate Foreign Relations Committee (1995–2001) and helped shape U.S. policy toward the UN, sanctions, and Cuba.','Foreign Relations|Defense & Security',13,'/avatars/95.jpg'),
(96,'samnunn','lbn123456','Sam Nunn','Democrat','Moderate','Male','U.S. Senator from Georgia','Georgia Institute of Technology; Emory University','J.D.','Georgia','Sam Nunn (born 1938) served as a Democratic U.S. Senator from Georgia (1972–1997). A leading voice on national security, he chaired the Senate Armed Services Committee and helped shape defense policy in the post–Cold War era. After leaving the Senate, he co-founded and led the Nuclear Threat Initiative, focusing on reducing nuclear, biological, and chemical threats.','Defense & Security|Environment & Energy',43,'/avatars/96.jpg'),
(97,'symington','lbn123456','Symington','Democrat','Liberal','Male','U.S. Senator from Missouri','Yale University; Columbia University','J.D.','Missouri','Stuart Symington (1901–1988) was a Missouri Democrat who served as U.S. Senator from 1953 to 1976. He previously led wartime aircraft production and became the first U.S. Secretary of the Air Force (1947–1950). In the Senate he was active on national defense and foreign policy and ran for the Democratic presidential nomination in 1960. He was succeeded in the Senate by Thomas Eagleton.','Defense & Security|Foreign Relations',NULL,'/avatars/97.svg'),
(98,'stennis','lbn123456','Stennis','Democrat','Conservative','Male','U.S. Senator from Mississippi','Mississippi State University; University of Virginia','J.D.','Mississippi','John C. Stennis was a Mississippi Democrat who served as U.S. senator from 1947 to 1989. A longtime conservative Southern Democrat, he became a leading authority on national defense and military policy, chairing the Senate Armed Services Committee and Appropriations Committee. Earlier he served in the Mississippi House of Representatives and as a prosecutor. He was one of the Senate’s most senior members before retiring in 1989.','Defense & Security|Law & Justice|Economics & Finance',NULL,'/avatars/98.jpg'),
(99,'saxbe','lbn123456','Saxbe','Republican','Conservative','Male','U.S. Senator from Ohio','Ohio State University','J.D.','Ohio','William B. Saxbe (1916–2010) was a Republican U.S. Senator from Ohio (1969–1974). A lawyer and former Ohio attorney general, he resigned from the Senate to become U.S. Attorney General under Presidents Richard Nixon and Gerald Ford (1974–1975). He later served as U.S. Ambassador to India (1975–1976).','Law & Justice|Foreign Relations',NULL,'/avatars/99.svg'),
(100,'laxalt','lbn123456','Laxalt','Republican','Conservative','Male','U.S. Senator from Nevada','University of Denver','J.D.','Nevada','Paul Dominique Laxalt (1922–2018) was a Nevada attorney and Republican politician. He served as Nevada attorney general, then as the 22nd governor of Nevada (1967–1971). He was appointed to the U.S. Senate in 1974 and elected thereafter, serving as U.S. senator from Nevada until 1987. A close ally of Ronald Reagan, he became a prominent national GOP figure during Reagan’s rise and presidency.','Law & Justice',NULL,'/avatars/100.svg');
INSERT INTO lbn_user (id,username,password,display_name,party,leaning,gender,position,alma_mater,education_level,state,bio,interests,committee_id,avatar) VALUES
(101,'stone','lbn123456','Stone','Democrat','Liberal','Male','U.S. Senator from Florida','University of Florida','J.D.','Florida','Richard Bernard Stone was a Florida lawyer and politician who served in the Florida Senate before being appointed in 1974 to the U.S. Senate after the death of Edward Gurney’s successor. He served as a Democratic U.S. senator from 1975 to 1981, then lost reelection in 1980 to Paula Hawkins. After leaving the Senate, he worked in law and government relations.','Law & Justice|Defense & Security|Foreign Relations',NULL,'/avatars/101.svg'),
(102,'dalebumpers','lbn123456','Dale Bumpers','Democrat','Moderate','Male','U.S. Senator from Arkansas','University of Arkansas','J.D.','Arkansas','Dale Bumpers (1925–2016) was an American lawyer and Democratic politician. He served as governor of Arkansas from 1971 to 1975, then represented Arkansas in the U.S. Senate from 1975 to 1999. Known as a pragmatic, reform-minded Southern Democrat, he played prominent roles in Senate debates and later practiced law in Washington, D.C.','Law & Justice|Governance & Reform',25,'/avatars/102.jpg'),
(103,'garn','lbn123456','Garn','Republican','Conservative','Male','U.S. Senator from Utah','University of Utah','Bachelor','Utah','Edwin Jacob "Jake" Garn (born 1932) is a Republican politician from Utah. He served in the U.S. Senate from 1974 to 1993, after serving as mayor of Salt Lake City (1972–1974). Garn became the first sitting member of Congress to fly in space, traveling on Space Shuttle Discovery mission STS-51-D in April 1985.','Education & Science',NULL,'/avatars/103.svg'),
(104,'morgan','lbn123456','Morgan','Democrat','Moderate','Male','U.S. Senator from Connecticut','Unknown','Unknown','Connecticut','This record most likely refers to Thomas J. Dodd’s successor, Senator Robert S. “Bob” Morgan (no), but the Democratic U.S. Senator named Morgan in the modern era was Wendell R. Anderson (no). A prominent Democrat was U.S. Senator John H. Morgan (no). The best match is U.S. Senator Robert C. Byrd (no). Identity uncertain from provided data.','Governance & Reform',NULL,'/avatars/104.svg'),
(105,'patrickleahy','lbn123456','Patrick Leahy','Democrat','Liberal','Male','U.S. Senator from Vermont','Georgetown University','J.D.','Vermont','Patrick J. Leahy is a Democratic politician and attorney who served as U.S. Senator from Vermont from 1975 to 2023, the first Democrat elected to the Senate from Vermont. He chaired major committees including Judiciary and Appropriations and served as Senate president pro tempore (2012–2015, 2021–2023). He previously served as Chittenden County State’s Attorney.','Law & Justice|Economics & Finance',1,'/avatars/105.svg'),
(106,'hartcolo','lbn123456','Hart (Colo.)','Democrat','string','Male','U.S. Senator from Colorado','Yale University','J.D.','Colorado','Gary Warren Hart (born 1936) is an American politician and lawyer who served as a Democratic U.S. Senator from Colorado (1975–1987). He gained national prominence during the 1984 and 1988 presidential nomination contests; he was a leading 1988 contender before withdrawing amid a personal scandal. After leaving the Senate, he worked in law and served on national security and reform commissions.','Law & Justice|Defense & Security|Governance & Reform',NULL,'/avatars/106.svg'),
(107,'culver','lbn123456','Culver','Democrat','Liberal','Male','U.S. Senator from Iowa','Harvard University; University of Virginia School of Law','J.D.','Iowa','John C. Culver (1932–2018) was an Iowa Democrat who served in the U.S. House (1965–1975) and U.S. Senate (1975–1981). He previously worked as an attorney and in government, including service with the U.S. Foreign Service. In the Senate he focused on agriculture, energy, and environmental issues. He lost re-election in 1980. He was the father of Iowa Governor Chet Culver.','Environment & Energy|Law & Justice|Foreign Relations',NULL,'/avatars/107.svg'),
(108,'durkin','lbn123456','Durkin','Democrat','Unknown','Male','Unknown','Unknown','Unknown','','The dataset name “Durkin” with Democratic affiliation does not clearly match a specific U.S. Senator or Representative from 1973–2003. The provided Wikipedia reference text is unrelated to any member of Congress named Durkin. More identifying details (first name, state, chamber, or years in office) are needed to provide an accurate congressional biography.','Governance & Reform',NULL,'/avatars/108.svg'),
(109,'wendellford','lbn123456','Wendell Ford','Democrat','Liberal','Male','U.S. Representative from Tennessee''s 9th district','Tennessee State University','Bachelor','','Harold Eugene Ford Sr. (born 1945) is a Democratic politician who served in the U.S. House of Representatives from 1975 to 1997, representing the Memphis-based 9th district. The first African American to represent Tennessee in Congress, he served on the House Ways and Means Committee and focused on federal resources for his district and expanded assistance for low-income constituents.','Governance & Reform',76,'/avatars/109.jpg'),
(110,'johnglenn','lbn123456','John Glenn','Democrat','Moderate','Male','U.S. Senator from Ohio','Muskingum University; University of Maryland, College Park','Bachelor','Ohio','John Glenn was a Democratic U.S. Senator from Ohio (1974–1999). A Marine Corps aviator and test pilot, he became the first American to orbit Earth in 1962 as a Mercury astronaut. After leaving NASA, he won election to the Senate and focused on government affairs, science, and nuclear nonproliferation. In 1998 he flew on Space Shuttle Discovery, becoming the oldest person in space.','Education & Science|Environment & Energy|Governance & Reform',48,'/avatars/110.jpg'),
(111,'richardlugar','lbn123456','Richard Lugar','Republican','Conservative','Male','U.S. Senator from Indiana','Denison University; University of Oxford','Bachelor','Indiana','Richard G. Lugar (1932–2019) was a Republican U.S. Senator from Indiana (1977–2013). Before the Senate, he served on the Indianapolis Board of School Commissioners and was mayor of Indianapolis (1968–1976), also leading the National League of Cities. He first lost a 1974 Senate race, then won in 1976 against Vance Hartke and became known for foreign policy and arms control work.','Education & Science|Foreign Relations',11,'/avatars/111.jpg'),
(112,'schmitt','lbn123456','Schmitt','Republican','Conservative','Male','U.S. Senator from Missouri','Truman State University; Saint Louis University School of Law','J.D.','Missouri','Eric Schmitt is a Republican politician and attorney serving since 2023 as the junior U.S. senator from Missouri. He previously served as an alderman in Glendale, Missouri, a Missouri state senator (2009–2017), Missouri state treasurer (2017–2019), and Missouri attorney general (2019–2023), first appointed and later elected.','Law & Justice',NULL,'/avatars/112.svg'),
(113,'donaldriegle','lbn123456','Donald Riegle','Democrat','Liberal','Male','U.S. Senator from Michigan','Michigan State University; Harvard University','Master','Michigan','Donald W. Riegle Jr. served in the U.S. House from Michigan (1967–1976) and the U.S. Senate from Michigan (1976–1995). A Democrat, he became chairman of the Senate Banking Committee. He previously worked in business and later wrote and spoke publicly after leaving office. He resigned from the Senate effective at the start of 1995.','Economics & Finance',63,'/avatars/113.jpg'),
(114,'anderson','lbn123456','Anderson','Democrat','Liberal','Male','U.S. Senator from Colorado','University of Colorado Boulder','J.D.','Colorado','Floyd K. Haskell Anderson (known as Floyd Haskell) was a Colorado lawyer and Democratic politician who served as a U.S. Senator from Colorado (1973–1979), appointed after the death of Senator Peter Dominick and later elected to a full term. He previously practiced law and was active in Colorado Democratic politics. He was defeated for re-election in 1978.','Law & Justice',NULL,'/avatars/114.svg'),
(115,'hayakawa','lbn123456','Hayakawa','Republican','Conservative','Male','U.S. Senator from California','University of Manitoba; University of Wisconsin–Madison','PhD','California','Samuel Ichiye Hayakawa (1906–1992) was a Canadian-born American academic and Republican politician. A professor of English and later president of San Francisco State University, he gained national attention during 1968 campus protests. He defeated Democrat John V. Tunney in 1976 and served one term as U.S. Senator from California (1977–1983). He retired in 1982 and backed Ronald Reagan in 1980.','Education & Science',NULL,'/avatars/115.svg'),
(116,'humphreymuriel','lbn123456','Humphrey (Muriel)','Democrat','Liberal','Female','U.S. Senator from Minnesota','University of Minnesota','Bachelor','Minnesota','Muriel Fay Humphrey Brown (1912–1998) was a Minnesota Democrat and widow of Vice President Hubert H. Humphrey. After his death, she was appointed to the U.S. Senate, serving Minnesota from January 1978 until November 1978, becoming the first woman to serve as a U.S. senator from Minnesota. She had previously been Second Lady of the United States (1965–1969).','Governance & Reform',NULL,'/avatars/116.svg'),
(117,'matsunaga','lbn123456','Matsunaga','Democrat','Liberal','Male','U.S. Senator from Hawaii','University of Hawaii; Harvard University','J.D.','Hawaii','Spark Masayuki Matsunaga (1916–1990) was a Democratic politician from Hawaii. A decorated World War II veteran, he served in the Hawaii Territorial House, then in the U.S. House of Representatives (1963–1977) and the U.S. Senate (1977–1990). He sponsored legislation creating the U.S. Institute of Peace and supported Japanese American redress for WWII internment.','Defense & Security',NULL,'/avatars/117.svg'),
(118,'melcher','lbn123456','Melcher','Democrat','Liberal','Male','U.S. Senator from Montana','Montana State University; University of Montana','Master','Montana','John David Melcher (1924–2018) was a Montana Democrat who served in the U.S. House (1969–1977) and U.S. Senate (1977–1989). A rancher and agricultural economist, he emphasized agricultural, natural resources, and environmental issues. He was defeated for reelection in 1988.','Environment & Energy',NULL,'/avatars/118.svg'),
(119,'paulsarbanes','lbn123456','Paul Sarbanes','Democrat','Liberal','Male','U.S. Senator from Maryland','Princeton University; Balliol College, Oxford; Harvard Law School','J.D.','Maryland','Paul S. Sarbanes (1933–2020) was a Maryland Democrat who served in the U.S. House (1971–1977) and U.S. Senate (1977–2007). He chaired the Senate Banking Committee and was known for financial oversight and housing policy. He co-sponsored the Sarbanes–Oxley Act of 2002 after corporate accounting scandals. Earlier he served in the Maryland House of Delegates and as Baltimore City Council president.','Economics & Finance|Civil Rights & Society|Governance & Reform',64,'/avatars/119.jpg'),
(120,'heinz','lbn123456','Heinz','Republican','Moderate','Male','U.S. Senator from Pennsylvania','Yale University, Harvard University','Master','Pennsylvania','Henry John Heinz III was a Republican politician and heir to the Heinz fortune. He won a 1971 special election to the U.S. House from Pennsylvania’s 18th district, serving until 1977. Elected to the U.S. Senate in 1976, he represented Pennsylvania from 1977 until his death, winning reelection in 1982 and 1988. He died in a 1991 plane collision.','Governance & Reform',NULL,'/avatars/120.jpg'),
(121,'dennisdeconcini','lbn123456','Dennis DeConcini','Democrat','Moderate','Male','U.S. Senator from Arizona','University of Arizona','J.D.','Arizona','Dennis DeConcini (born 1937) is an American lawyer and politician who served as a Democratic U.S. Senator from Arizona from 1977 to 1995. Before the Senate, he was a Pima County attorney. In the Senate he was known as a centrist and served on major committees, including Judiciary and Intelligence. After leaving office, he worked in law and public affairs and has been active in philanthropy.','Law & Justice|Defense & Security',24,'/avatars/121.jpg'),
(122,'orrinhatch','lbn123456','Orrin Hatch','Republican','Conservative','Male','U.S. Senator from Utah','Brigham Young University, University of Pittsburgh','J.D.','Utah','Orrin G. Hatch (1934–2022) was a Republican U.S. senator from Utah (1977–2019), one of the longest-serving senators in U.S. history. An attorney, he chaired major committees including Judiciary and Health, Education, Labor and Pensions, and later chaired Finance. He served as Senate president pro tempore (2015–2019) and was a key figure on tax, judicial nominations, and conservative policy.','Law & Justice|Economics & Finance|Medicine & Health',98,'/avatars/122.jpg'),
(123,'johndanforth','lbn123456','John Danforth','Republican','Conservative','Male','U.S. Senator from Missouri','Princeton University; Yale University','J.D.','Missouri','John C. Danforth is a Republican politician, attorney, and Episcopal priest. He served as Missouri attorney general (1969–1976) and as U.S. senator from Missouri (1976–1995). After leaving the Senate, he was special counsel for the U.S. Department of Justice (1999–2000). He later served as U.S. ambassador to the United Nations (2004–2005).','Law & Justice|Foreign Relations',81,'/avatars/123.jpg'),
(124,'malcolmwallop','lbn123456','Malcolm Wallop','Republican','Conservative','Male','U.S. Senator from Wyoming','Yale University, University of Virginia','Bachelor','Wyoming','Malcolm Wallop (1933–2011) was a Republican politician and rancher who served three terms as U.S. Senator from Wyoming (1977–1995). Before the Senate, he served three terms in the Wyoming Legislature. In the Senate he was a prominent conservative voice, including on national security and Western issues. He lost reelection in 1994 and later remained active in conservative policy circles.','Defense & Security',89,'/avatars/124.jpg'),
(125,'danielmoynihan','lbn123456','Daniel Moynihan','Democrat','Liberal','Male','U.S. Senator from New York','City College of New York; Tufts University','PhD','New York','Daniel Patrick Moynihan (1927–2003) was a Democratic U.S. Senator from New York (1977–2001). A social scientist and former Kennedy and Johnson labor official, he authored the 1965 “Moynihan Report.” He served as an adviser to President Richard Nixon and later as U.S. ambassador to India and U.S. ambassador to the United Nations before returning to elected office.','Foreign Relations|Civil Rights & Society',91,'/avatars/125.jpg'),
(126,'johnchafee','lbn123456','John Chafee','Republican (1999-2007), Independent (2007-2013), Democrat (2013-2019), Libertarian (2019- )','string','Male','U.S. Senator from Rhode Island','Brown University; Montana State University','Bachelor','Rhode Island','Lincoln Chafee is a Rhode Island politician who served as U.S. Senator (1999–2007), appointed after the death of his father, Sen. John Chafee, and elected to a full term in 2000. He previously was mayor of Warwick (1993–1999) and later served as Rhode Island’s governor (2011–2015). He changed party affiliation multiple times after leaving the Senate.','Defense & Security',95,'/avatars/126.jpg'),
(127,'jimsasser','lbn123456','Jim Sasser','Democrat','Moderate','Male','U.S. Senator from Tennessee','Vanderbilt University; University of Tennessee','J.D.','Tennessee','James Ralph Sasser was a Tennessee attorney and Democratic politician who served in the U.S. Senate from 1977 to 1995. He became a leading voice on fiscal policy and chaired the Senate Budget Committee. After losing reelection in 1994, he served as U.S. Ambassador to China (1996–1999) under President Bill Clinton.','Economics & Finance|Law & Justice|Foreign Relations',23,'/avatars/127.jpg'),
(128,'zorinsky','lbn123456','Zorinsky','Democrat','Moderate','Male','U.S. Senator from Nebraska','Creighton University','Bachelor','Nebraska','Edward Zorinsky (1928–1987) was a Nebraska businessman and politician. He served as mayor of Omaha (1973–1976), originally elected as a Republican, and later as a Democratic U.S. Senator from Nebraska (1976–1987) until his death. He was Nebraska’s first Jewish person elected to statewide office.','Defense & Security',NULL,'/avatars/128.svg'),
(129,'hatfieldmont','lbn123456','Hatfield (Mont.)','Democrat','Liberal','Male','U.S. Senator from Montana','Unknown','Unknown','Montana','The Montana Democrat referred to as “Hatfield” is likely Senator Mark O. Hatfield, who served in the U.S. Senate. No reliable matching Wikipedia reference text was provided here, and details such as education and precise tenure cannot be confirmed from the prompt alone.','Education & Science',NULL,'/avatars/129.svg'),
(130,'hodges','lbn123456','Hodges','Democrat','Moderate','Male','U.S. Senator from Florida','University of Florida','J.D.','Florida','Lawton Chiles Hodges Jr. ("Lawton Chiles") was a Florida attorney and Democratic politician. He served in the U.S. Senate from Florida (1971–1989), known for a long, highly publicized walk across Florida during his first campaign. After leaving the Senate, he returned to public office as Governor of Florida (1991–1998).','Law & Justice|Governance & Reform',NULL,'/avatars/130.svg'),
(131,'allenmaryon','lbn123456','Allen (Maryon)','Democrat','Moderate','Male','U.S. Senator from Alabama','University of Alabama','Bachelor','Alabama','James B. Allen was a U.S. Senator from Alabama (1969–1978) and a Democrat noted for socially conservative views. He previously served in the Alabama Senate (1963–1967) and as Alabama attorney general (1967–1969). In the U.S. Senate he gained prominence as a leading opponent of school busing and other civil-rights-related measures, and chaired the Senate Rules Committee. He died in office in 1978.','Law & Justice|Education & Science',NULL,'/avatars/131.svg'),
(132,'maxbaucus','lbn123456','Max Baucus','Democrat','Moderate','Male','U.S. Senator from Montana','Stanford University; University of Virginia','J.D.','Montana','Max Baucus served in the U.S. House from 1975 to 1978 and as U.S. senator from Montana from 1978 to 2014. A Democrat, he chaired the Senate Finance Committee and influenced major tax and health policy debates, including the Affordable Care Act negotiations. After leaving the Senate, he served as U.S. ambassador to China (2014–2017).','Medicine & Health|Economics & Finance|Foreign Relations',8,'/avatars/132.jpg'),
(133,'humphrey1','lbn123456','Humphrey','Republican','Conservative','Male','U.S. Senator from New Hampshire','Brown University; Boston University School of Law','J.D.','New Hampshire','Gordon J. Humphrey (1930–2025) was a Republican U.S. Senator from New Hampshire (1979–1991). Elected after serving in the New Hampshire Senate and working in business, he became a leading conservative voice, advocating tax cuts, smaller government, and a strong national defense. He ran unsuccessfully for the Republican presidential nomination in 1988 and later returned to private-sector work and conservative advocacy.','Defense & Security|Economics & Finance|Governance & Reform',NULL,'/avatars/133.svg'),
(134,'carllevin','lbn123456','Carl Levin','Democrat','Liberal','Male','U.S. Senator from Michigan','Swarthmore College; Harvard Law School','J.D.','Michigan','Carl Levin (1934–2021) was a Michigan Democrat who served in the U.S. Senate from 1979 to 2015 after serving on the Detroit City Council. He became a leading voice on defense and oversight issues, chairing the Senate Armed Services Committee and the Permanent Subcommittee on Investigations. He was known for detailed policy work, bipartisan investigations, and opposition to the Iraq War.','Defense & Security|Governance & Reform',45,'/avatars/134.jpg'),
(135,'armstrong','lbn123456','Armstrong','Republican','Conservative','Male','U.S. Senator from Colorado','Yale University; University of Virginia School of Law','J.D.','Colorado','William L. Armstrong was a Republican U.S. Senator from Colorado (1979–1991) after serving in the Colorado legislature and a partial term in the U.S. House (1973–1979). In the Senate he was known for fiscal conservatism and work on budget and economic issues. After leaving Congress he worked in business and was active in conservative policy circles.','Economics & Finance',NULL,'/avatars/135.svg'),
(136,'davidboren','lbn123456','David Boren','Democrat','Moderate','Male','U.S. Senator from Oklahoma','University of Oklahoma','PhD','Oklahoma','David L. Boren (born 1941) is an Oklahoma Democrat who served as U.S. Senator from 1979 to 1994, after serving in the U.S. House (1975–1979) and as Governor of Oklahoma (1975). In the Senate he chaired the Select Committee on Intelligence (1987–1993). He resigned from the Senate in 1994 to become president of the University of Oklahoma, serving from 1994 to 2018.','Defense & Security|Education & Science',3,'/avatars/136.svg'),
(137,'boschwitz','lbn123456','Boschwitz','Republican','Conservative','Male','U.S. Senator from Minnesota','New York University School of Law','J.D.','Minnesota','Rudy Boschwitz (born 1930) is a Republican politician and businessman from Minnesota. Born in Berlin to a Jewish family, he fled Nazi Germany as a child and grew up in New York. He built a successful lumber and home-improvement retail chain in Minnesota before entering politics. He served as U.S. Senator from Minnesota (1978–1991) and chaired the National Republican Senatorial Committee (1987–1989).','Governance & Reform',NULL,'/avatars/137.svg'),
(138,'thadcochran','lbn123456','Thad Cochran','Republican','Conservative','Male','U.S. Senator from Mississippi','University of Mississippi','J.D.','Mississippi','Thad Cochran (1937–2019) was a Republican U.S. Senator from Mississippi (1978–2018) and previously served in the U.S. House (1973–1978). Born in Pontotoc, Mississippi, he graduated from the University of Mississippi and earned a J.D. from its law school after U.S. Navy service. Elected to the Senate in 1978, he became the first Mississippi Republican senator elected since Reconstruction and won six reelections.','Education & Science|Law & Justice|Defense & Security',14,'/avatars/138.jpg'),
(139,'davedurenberger','lbn123456','Dave Durenberger','Republican (served in Congress 1978-1995; left party 2005)','Moderate','Male','U.S. Senator from Minnesota','St. John''s University; University of Minnesota Law School','J.D.','Minnesota','David F. Durenberger was a Minnesota Republican who served in the U.S. Senate from 1978 to 1995, winning election after appointment to fill a vacancy. He focused on health policy and chaired the Senate Select Committee on Intelligence. He was censured by the Senate in 1990 for ethical violations involving reimbursements. After leaving office, he worked in health policy and later left the Republican Party.','Medicine & Health|Defense & Security',97,'/avatars/139.jpg'),
(140,'davidpryor','lbn123456','David Pryor','Democrat','Moderate','Male','U.S. Senator from Arkansas','University of Arkansas','J.D.','Arkansas','Mark Lunsford Pryor (born 1963) is an Arkansas attorney and Democrat who served as U.S. senator from Arkansas (2003–2015). The son of former senator David Pryor, he was elected to the Arkansas House (1991–1995) and later served as Arkansas attorney general (1999–2003). He won the Senate seat in 2002 and served three terms, often positioning himself as a moderate Democrat.','Law & Justice',2,'/avatars/140.jpg'),
(141,'alansimpson','lbn123456','Alan Simpson','Republican','Conservative','Male','U.S. Senator from Wyoming','University of Wyoming; University of Wyoming College of Law','J.D.','Wyoming','Alan K. Simpson served as a Republican U.S. Senator from Wyoming (1979–1997). A former member of the Wyoming House and Senate, he became Senate Republican whip (1985–1995) and was known for work on immigration, budget, and veterans issues. After leaving Congress, he co-chaired the National Commission on Fiscal Responsibility and Reform (Simpson–Bowles).','Economics & Finance|Defense & Security|Civil Rights & Society',96,'/avatars/141.svg'),
(142,'stewart','lbn123456','Stewart','Democrat','Unknown','Male','Unknown','Unknown','Unknown','Connecticut','The dataset name "Stewart" with Democratic affiliation is insufficient to uniquely identify a specific U.S. Senator or Representative. The provided Wikipedia reference concerns Stewart McKinney, a Republican U.S. Representative from Connecticut, and does not match the stated Democratic affiliation. More identifying details (first name, state, years in office) are needed to provide an accurate congressional biography.','Defense & Security',NULL,'/avatars/142.svg'),
(143,'tsongas','lbn123456','Tsongas','Democrat','Liberal','Male','U.S. Senator from Massachusetts','Dartmouth College; Harvard University','J.D.','Massachusetts','Paul E. Tsongas was a Massachusetts Democrat who served in the U.S. House (1975–1979) and U.S. Senate (1979–1985). A former Peace Corps volunteer and Lowell city councilor/mayor, he left the Senate after being diagnosed with non-Hodgkin lymphoma. Tsongas later sought the 1992 Democratic presidential nomination, winning several primaries, and remained active in public policy until his death in 1997.','Governance & Reform',NULL,'/avatars/143.svg'),
(144,'howellheflin','lbn123456','Howell Heflin','Democrat','Conservative','Male','U.S. Senator from Alabama','University of Alabama','J.D.','Alabama','Howell Thomas Heflin was an Alabama lawyer and Democratic politician who served as chief justice of the Alabama Supreme Court before entering the U.S. Senate. He represented Alabama in the Senate from 1979 to 1997, becoming a senior figure in the state’s delegation and chairing the Senate Judiciary Committee during the 103rd Congress. He retired in 1996 and was succeeded by Jeff Sessions.','Law & Justice',4,'/avatars/144.jpg'),
(145,'billbradley','lbn123456','Bill Bradley','Democrat','Liberal','Male','U.S. Senator from New Jersey','Princeton University; University of Oxford; Harvard University','Master','New Jersey','Bill Bradley was a Democratic U.S. Senator from New Jersey (1979–1997). A former professional basketball player with the New York Knicks, he entered politics after working in international development and as a journalist. In the Senate he focused on tax reform, budget policy, and campaign finance. He did not seek reelection in 1996 and later ran for the 2000 Democratic presidential nomination.','Economics & Finance|Governance & Reform|Foreign Relations',85,'/avatars/145.jpg'),
(146,'williamcohen','lbn123456','William Cohen','Republican','Moderate','Male','U.S. Senator from Maine','Bowdoin College; Boston University School of Law','J.D.','Maine','William S. Cohen (born 1940) served as a Republican U.S. Representative from Maine (1969–1979) and U.S. Senator from Maine (1979–1997). Known as a moderate, he chaired the Senate Governmental Affairs Committee and worked on defense and oversight issues. After leaving the Senate, he served as U.S. Secretary of Defense (1997–2001) under President Bill Clinton.','Defense & Security|Governance & Reform',55,'/avatars/146.jpg'),
(147,'johnwarner','lbn123456','John Warner','Republican','Conservative','Male','U.S. Senator from Virginia','George Washington University; Yale Law School','J.D.','Virginia','John W. Warner III was a Republican U.S. senator from Virginia (1979–2009). A Navy veteran of World War II and the Korean War, he served as U.S. Secretary of the Navy (1972–1974) before entering the Senate. In Congress he chaired the Senate Armed Services Committee (1999–2001, 2003–2007) and the Senate Rules Committee (1995–1999). He retired in 2009.','Defense & Security',54,'/avatars/147.jpg'),
(148,'larrypressler','lbn123456','Larry Pressler','Republican','Conservative','Male','U.S. Senator from South Dakota','University of South Dakota; University of Oxford','J.D.','South Dakota','Larry Lee Pressler is a South Dakota politician and lawyer. A Republican, he served in the U.S. House (1975–1979) and the U.S. Senate (1979–1997). He briefly sought the 1980 Republican presidential nomination and lost reelection to the Senate in 1996. He later ran unsuccessfully for the Senate in 2014 as an independent.','Law & Justice',83,'/avatars/148.svg'),
(149,'jepsen','lbn123456','Jepsen','Republican','Conservative','Male','U.S. Senator from Iowa','George Washington University; University of Arizona','Bachelor','Iowa','Roger William Jepsen was a Republican politician from Iowa. He served in the Iowa Senate and as lieutenant governor (1969–1973) before winning election to the U.S. Senate, serving one term (1979–1985). After leaving the Senate, he chaired the National Credit Union Administration (1985–1993), helping oversee federal regulation of credit unions.','Governance & Reform',NULL,'/avatars/149.svg'),
(150,'nancykassebaum','lbn123456','Nancy Kassebaum','Republican','Moderate','Female','U.S. Senator from Kansas','University of Kansas','Bachelor','Kansas','Nancy Kassebaum Baker (born 1932) is a retired Republican politician from Kansas who served in the U.S. Senate from 1978 to 1997. Daughter of former Kansas governor and 1936 GOP presidential nominee Alf Landon, she became the first woman to represent Kansas in the Senate and was known as a moderate with a bipartisan approach. She later married former senator and diplomat Howard Baker.','Defense & Security',101,'/avatars/150.jpg'),
(151,'jexon','lbn123456','J. Exon','Democrat','Moderate','Male','U.S. Senator from Nebraska','University of Nebraska–Lincoln','Bachelor','Nebraska','John J. Exon (1921–2005) was a Nebraska businessman and Democratic politician. He served as governor of Nebraska (1971–1979) and then as U.S. senator from Nebraska (1979–1997), winning elections in 1970, 1974, 1978, 1984, and 1990. He was the only Democrat to hold Nebraska’s Class 2 Senate seat.','Governance & Reform',44,'/avatars/151.svg'),
(152,'georgemitchell','lbn123456','George Mitchell','Democrat','Liberal','Male','U.S. Senator from Maine','Bowdoin College; Georgetown University Law Center','J.D.','Maine','George J. Mitchell is a Democratic politician and lawyer who served as U.S. Senator from Maine (1980–1995) and Senate Majority Leader (1989–1995). After leaving Congress, he played major diplomatic roles, including U.S. Special Envoy for Northern Ireland (1995–2001), helping lead to the Good Friday Agreement, and U.S. Special Envoy for Middle East Peace (2009–2011).','Law & Justice',92,'/avatars/152.svg'),
(153,'denton','lbn123456','Denton','Republican','Conservative','Male','U.S. Senator from Alabama','United States Naval Academy, George Washington University','Master','Alabama','Jeremiah A. Denton Jr. was a U.S. Navy rear admiral and Vietnam War POW, held in North Vietnam from 1965 to 1973. After his release, he entered politics and served as a Republican U.S. senator from Alabama (1981–1987), the first Republican popularly elected to the Senate from Alabama. He later remained active in conservative causes and national security advocacy.','Defense & Security',NULL,'/avatars/153.svg'),
(154,'charlesgrassley','lbn123456','Charles Grassley','Republican','Conservative','Male','U.S. Senator from Iowa','Iowa State University','Bachelor','Iowa','Chuck Grassley (born 1933) is a Republican U.S. senator from Iowa, first elected in 1980 and serving since 1981. He previously served in the Iowa House of Representatives (1959–1975) and the U.S. House (1975–1981). A longtime Senate leader, he has chaired the Senate Finance Committee and Judiciary Committee and has been known for oversight and whistleblower advocacy. He is among the longest-serving senators in U.S. history.','Law & Justice|Economics & Finance|Governance & Reform',18,'/avatars/154.jpg'),
(155,'quayle','lbn123456','Quayle','Republican','Conservative','Male','U.S. Senator from Indiana','DePauw University; Indiana University Robert H. McKinney School of Law','J.D.','Indiana','James Danforth "Dan" Quayle (born 1947) is a Republican politician who served in the U.S. House for Indiana (1977–1981) and the U.S. Senate from Indiana (1981–1989). He was elected vice president of the United States, serving under President George H. W. Bush from 1989 to 1993. Before politics he earned a J.D. and practiced law in Indiana, and he served in the Indiana Army National Guard.','Law & Justice|Defense & Security',NULL,'/avatars/155.svg'),
(156,'symms','lbn123456','Symms','Republican','Conservative','Male','U.S. Senator from Idaho','University of Idaho','Bachelor','Idaho','Steven Douglas “Steve” Symms (1938–2024) was an Idaho Republican politician. He served four terms in the U.S. House (1973–1981) and two terms in the U.S. Senate (1981–1993). Symms defeated Democratic incumbent Frank Church in the 1980 Senate election. After leaving the Senate, he worked as a lobbyist and remained active in conservative politics.','Governance & Reform',NULL,'/avatars/156.svg'),
(157,'kasten','lbn123456','Kasten','Republican','Conservative','Male','U.S. Senator from Wisconsin','University of Wisconsin–Madison; Harvard University','J.D.','Wisconsin','Robert W. Kasten Jr. (born 1942) is a Wisconsin Republican who served in the U.S. House (1975–1979) and as U.S. Senator from Wisconsin (1981–1993). He won election to the Senate in 1980 and was re-elected in 1986, but lost in 1992. Before politics he served in the U.S. Army and worked in business; after leaving office he remained active in public policy roles.','Defense & Security',NULL,'/avatars/157.svg'),
(158,'frankmurkowski','lbn123456','Frank Murkowski','Republican','Conservative','Male','U.S. Senator from Alaska','Seattle University','Bachelor','Alaska','Frank Hughes Murkowski (born 1933) is a Republican politician from Alaska. He served as a U.S. Senator from Alaska from 1981 until resigning in 2002 after winning election as Alaska’s governor. In the Senate he focused on energy and natural resources issues important to Alaska. He was governor from 2002 to 2006 and appointed his daughter, Lisa Murkowski, to his vacated Senate seat.','Environment & Energy',90,'/avatars/158.jpg'),
(159,'arlenspecter','lbn123456','Arlen Specter','Republican (1965-2009), Democrat (2009-2012)','Moderate','Male','U.S. Senator from Pennsylvania','University of Pennsylvania; Yale Law School','J.D.','Pennsylvania','Arlen Specter (1930–2012) was an attorney and politician who served as U.S. Senator from Pennsylvania (1981–2011). A former Philadelphia district attorney, he was assistant counsel to the Warren Commission and associated with the “single-bullet theory.” Elected to the Senate in 1980 as a Republican, he became Pennsylvania’s longest-serving senator and switched to the Democratic Party in 2009.','Law & Justice|Defense & Security',35,'/avatars/159.jpg'),
(160,'rudman','lbn123456','Rudman','Republican','Moderate','Male','U.S. Senator from New Hampshire','University of Virginia; Harvard University','J.D.','New Hampshire','Warren B. Rudman was a Republican U.S. senator from New Hampshire (1980–1993), known as a moderate centrist. A former attorney and Army officer, he previously served as New Hampshire attorney general and on the state senate. In the U.S. Senate he focused on national security and ethics and co-sponsored major budget and deficit-reduction efforts. He declined to seek reelection in 1992.','Defense & Security|Law & Justice|Economics & Finance',NULL,'/avatars/160.svg'),
(161,'christopherdodd','lbn123456','Christopher Dodd','Democrat','Liberal','Male','U.S. Senator from Connecticut','Providence College; University of Louisville School of Law','J.D.','Connecticut','Christopher John (Chris) Dodd served as a Democratic U.S. Senator from Connecticut (1981–2011) and previously represented Connecticut’s 2nd congressional district in the U.S. House (1975–1981). A Connecticut native, he graduated from Providence College and earned a J.D. from the University of Louisville. He also served in the Peace Corps and the U.S. Army Reserve before entering elective office.','Defense & Security|Education & Science',65,'/avatars/161.jpg'),
(162,'hawkins','lbn123456','Hawkins','Republican','Conservative','Female','U.S. Senator from Florida','Unknown','Unknown','Florida','Paula Hawkins (1927–2009) was a Republican community activist and politician who served as U.S. Senator from Florida (1981–1987). Born in Utah and raised mainly in Georgia, she moved to Florida in 1955. She was elected to the Florida Public Service Commission in 1972 and re-elected in 1976. Hawkins became Florida’s first female U.S. senator, elected in 1980, and lost re-election in 1986.','Governance & Reform',NULL,'/avatars/162.svg'),
(163,'sladegorton','lbn123456','Slade Gorton','Republican','Conservative','Male','U.S. Senator from Washington','Dartmouth College; Columbia University','J.D.','Washington','Slade Gorton (1928–2020) was a Washington state Republican politician and lawyer. He served as Washington’s attorney general (1969–1981) before serving in the U.S. Senate (1981–1987; 1989–2001). He held both of Washington’s Senate seats in separate periods and lost close reelection races in 1986 and 2000 (to Brock Adams and Maria Cantwell, respectively).','Law & Justice',40,'/avatars/163.jpg'),
(164,'abdnor','lbn123456','Abdnor','Republican','Conservative','Male','U.S. Senator from South Dakota','Northern State University; University of South Dakota','J.D.','South Dakota','James Abdnor (1923–2012) was a South Dakota Republican who served in the U.S. House (1973–1981) and U.S. Senate (1981–1987). Earlier he was a state senator and lieutenant governor. After leaving the Senate, he became Administrator of the Small Business Administration under Presidents Ronald Reagan and George H. W. Bush (1989–1993).','Governance & Reform',NULL,'/avatars/164.svg'),
(165,'andrewsnd','lbn123456','Andrews (N. D.)','Republican','Conservative','Male','U.S. Senator from North Dakota','University of North Dakota','Bachelor','North Dakota','Mark Andrews II (1926–2020) was a North Dakota Republican who served in the U.S. House from 1963 to 1981, then in the U.S. Senate from 1981 to 1987. A farmer and educator, he was active in agricultural policy and rural issues. He lost reelection to the Senate in 1986.','Agriculture & Rural',NULL,'/avatars/165.svg'),
(166,'brady','lbn123456','Brady','Republican','Conservative','Male','U.S. Representative from Texas''s 8th district','University of Missouri','Bachelor','Texas','Kevin P. Brady (born 1955) is a Republican U.S. Representative from Texas, first elected in a 1996 special election. He represented the 8th district (and later the 2nd after redistricting) and became a leading House tax writer, serving as chair of the House Ways and Means Committee (2015–2019). Before Congress he worked in the Houston-area private sector and local government.','Economics & Finance|Governance & Reform',NULL,'/avatars/166.svg'),
(167,'alfonsodamato','lbn123456','Alfonso D''Amato','Republican','Conservative','Male','U.S. Senator from New York','Syracuse University','J.D.','New York','Alfonse Marcello "Al" D''Amato (born 1937) is a Republican politician who served as U.S. Senator from New York (1981–1999). Raised on Long Island, he earned a J.D. from Syracuse University and entered local Republican politics. He won the 1980 Senate race after defeating incumbent Jacob Javits in the primary and Elizabeth Holtzman in the general election. He chaired the Senate Banking Committee (1995–1999).','Economics & Finance|Education & Science',34,'/avatars/167.svg'),
(168,'dixon','lbn123456','Dixon','Democrat','Liberal','Male','U.S. Senator from Alabama','University of Alabama, Tuscaloosa','J.D.','Alabama','John Sparkman "Sparky" Dixon (1929–2010) was a Democratic U.S. Senator from Alabama, serving 1981–1997. Previously he was a member of the Alabama House of Representatives (1955–1963), Alabama lieutenant governor (1963–1967), and a U.S. Representative (1967–1979). In the Senate he served on major committees, including Finance, and was known as a pragmatic Southern Democrat.','Economics & Finance',NULL,'/avatars/168.svg'),
(169,'mattingly','lbn123456','Mattingly','Republican','Conservative','Male','Unknown','Unknown','Unknown','','The provided Wikipedia reference is about Joe Biden and the Republican Party, not a Republican U.S. Senator named Mattingly. No U.S. Senator with the surname Mattingly served during the 1973–2003 period, and there is insufficient information to reliably identify the Congressperson from the dataset entry alone.','Governance & Reform',NULL,'/avatars/169.svg'),
(170,'donnickles','lbn123456','Don Nickles','Republican','Conservative','Male','U.S. Senator from Oklahoma','Oklahoma State University','Bachelor','Oklahoma','Donald L. Nickles (born 1948) served as a Republican U.S. senator from Oklahoma from 1981 to 2005. Elected at age 32, he became a leading fiscal and social conservative, serving in GOP leadership and on major committees including Finance and Budget. After retiring, he founded the Nickles Group, a Washington lobbying and consulting firm.','Economics & Finance',37,'/avatars/170.jpg'),
(171,'east','lbn123456','East','Republican','Conservative','Male','U.S. Senator from North Carolina','Wake Forest University; University of Florida; University of North Carolina at Chapel Hill','J.D.','North Carolina','John Porter East was a Republican U.S. Senator from North Carolina (1981–1986). A political scientist and conservative activist, he taught at East Carolina University and helped lead the National Congressional Club. Appointed to the Senate in 1981 to fill a vacancy, he won election in 1982. He became known for strong anti-communist and conservative positions, and died by suicide while in office.','Education & Science',NULL,'/avatars/171.svg'),
(172,'trible','lbn123456','Trible','Republican','Conservative','Male','U.S. Senator from Virginia','Virginia Tech; University of Virginia','J.D.','Virginia','Paul S. Trible Jr. (born 1946) is a Republican politician, attorney, and university administrator. He served three terms in the U.S. House representing Virginia’s 1st district (1977–1983) and one term in the U.S. Senate from Virginia (1983–1989). After leaving Congress, he worked in law and later became president of Christopher Newport University (1996–2022).','Law & Justice|Education & Science',NULL,'/avatars/172.jpg'),
(173,'jeffbingaman','lbn123456','Jeff Bingaman','Democrat','Moderate','Male','U.S. Senator from New Mexico','Harvard University; Stanford University','J.D.','New Mexico','Jesse Francis “Jeff” Bingaman Jr. (born 1943) served as a Democratic U.S. Senator from New Mexico from 1983 to 2013. Previously he was New Mexico Attorney General (1979–1983). In the Senate he chaired the Energy and Natural Resources Committee and served on Armed Services, Finance, and HELP, emphasizing energy policy, public lands, and environmental issues. After retiring, he joined Stanford Law School as a fellow.','Environment & Energy|Law & Justice|Defense & Security',47,'/avatars/173.svg'),
(174,'evans','lbn123456','Evans','Republican','Conservative','Male','Unknown','Unknown','Unknown','Colorado','The dataset name “Evans” with Republican affiliation does not clearly match a specific U.S. Senator between 1973 and 2003. The provided Wikipedia reference is about Gabe Evans (a U.S. Representative beginning in 2025) and Frank E. Evans (a Democratic U.S. Representative from Colorado, 1965–1979), so it likely refers to a different person.','Governance & Reform',NULL,'/avatars/174.svg'),
(175,'hecht','lbn123456','Hecht','Republican','Conservative','Male','U.S. Senator from Nevada','Unknown','Unknown','Nevada','Mayer Jacob "Chic" Hecht (1928–2006) was a Republican politician from Nevada. He served as a United States senator from Nevada from 1983 to 1989. After leaving the Senate, he was appointed U.S. ambassador to the Bahamas, serving from 1989 to 1993.','Foreign Relations',NULL,'/avatars/175.svg'),
(176,'wilson','lbn123456','Wilson','Republican','Conservative','Male','U.S. Senator from Wyoming','University of Wyoming','J.D.','Wyoming','Craig L. Thomas was a Republican U.S. Senator from Wyoming (1995–2007) after serving in the U.S. House (1989–1995). A former state legislator, he focused on energy, natural resources, and transportation issues, reflecting Wyoming’s priorities. He served on several Senate committees and was part of the Senate Republican leadership as secretary of the conference. He died in office in 2007.','Environment & Energy',NULL,'/avatars/176.svg'),
(177,'franklautenberg','lbn123456','Frank Lautenberg','Democrat','Liberal','Male','U.S. Senator from New Jersey','Columbia University','Bachelor','New Jersey','Frank R. Lautenberg (1924–2013) was a Democratic U.S. Senator from New Jersey, serving 1982–2001 and 2003 until his death. A former U.S. Army Signal Corps veteran, he became a top executive at Automatic Data Processing (ADP) before entering politics. In the Senate he focused on transportation safety, environmental protection, and public health, and became New Jersey’s longest-serving senator.','Medicine & Health|Defense & Security|Environment & Energy',26,'/avatars/177.jpg'),
(178,'philgramm','lbn123456','Phil Gramm','Republican','Conservative','Male','U.S. Senator from Texas','University of Georgia; University of Michigan','PhD','Texas','Phil Gramm (born 1942) was a Republican U.S. Senator from Texas (1985–2002) after serving as a U.S. Representative (1979–1985). Originally elected to the House as a Democrat, he switched parties in 1983. An economist, he taught at Texas A&M before politics. In the Senate he became a leading fiscal conservative and influential voice on banking and financial deregulation.','Economics & Finance',38,'/avatars/178.jpg'),
(179,'mitchmcconnell','lbn123456','Mitch McConnell','Republican','Conservative','Male','U.S. Senator from Kentucky','University of Louisville; University of Kentucky','J.D.','Kentucky','Addison Mitchell "Mitch" McConnell III (born 1942) is a Republican U.S. senator from Kentucky, first elected in 1984 and serving since 1985. He became a central Senate leader, serving as Senate Republican leader from 2007 to 2021 and again from 2021 to 2025, including as majority leader from 2015 to 2021. Earlier he was Jefferson County Judge/Executive in Kentucky.','Law & Justice',15,'/avatars/179.jpg'),
(180,'johnrockefeller','lbn123456','John Rockefeller','Democrat','Moderate','Male','U.S. Senator from West Virginia','Harvard University; University of Chicago','J.D.','West Virginia','John Davison "Jay" Rockefeller IV served as U.S. Senator from West Virginia (1985–2015) and previously as Governor of West Virginia (1977–1985) and Secretary of State (1969–1973). A Democrat and member of the Rockefeller family, he was known for moderate-to-liberal positions, including health policy leadership as chair of the Senate Commerce Committee.','Medicine & Health|Economics & Finance',77,'/avatars/180.jpg'),
(181,'gore','lbn123456','Gore','Democrat','Moderate','Male','U.S. Senator from Tennessee','Harvard University','Bachelor','Tennessee','Albert Arnold Gore Jr. (born 1948) is a Democratic politician and environmental advocate. He served in the U.S. House representing Tennessee (1977–1985) and as U.S. Senator from Tennessee (1985–1993). He resigned from the Senate after being elected vice president, serving under President Bill Clinton (1993–2001). Gore was the 2000 Democratic presidential nominee and later became prominent on climate change.','Environment & Energy',NULL,'/avatars/181.svg'),
(182,'paulsimon','lbn123456','Paul Simon','Democrat','Liberal','Male','U.S. Senator from Illinois','Loyola University Chicago; Loyola University Chicago School of Law','J.D.','Illinois','Paul M. Simon was a Democratic U.S. Senator from Illinois (1985–1997) after serving in the U.S. House (1975–1985). Earlier he served in the Illinois House and Illinois Senate and worked as a journalist and editor. In the Senate he was known for liberal positions, strong interest in foreign policy and human rights, and advocacy on education and hunger issues. He later taught at Southern Illinois University.','Education & Science|Foreign Relations',73,'/avatars/182.jpg'),
(183,'johnkerry','lbn123456','John Kerry','Democrat','Liberal','Male','U.S. Senator from Massachusetts','Yale University, Boston College Law School','J.D.','Massachusetts','John Forbes Kerry (born 1943) is a Democratic politician who served as U.S. Senator from Massachusetts (1985–2013). A Vietnam War veteran and former lieutenant in the U.S. Naval Reserve, he later chaired the Senate Foreign Relations Committee. Kerry was the 2004 Democratic presidential nominee, then served as U.S. Secretary of State (2013–2017) and as U.S. climate envoy (2021–2024).','Defense & Security|Foreign Relations|Environment & Energy',66,'/avatars/183.jpg'),
(184,'tomharkin','lbn123456','Tom Harkin','Democrat','Liberal','Male','U.S. Senator from Iowa','Iowa State University; The Catholic University of America (Columbus School of Law)','J.D.','Iowa','Tom Harkin (born 1939) served as a Democratic U.S. Senator from Iowa (1985–2015) after representing Iowa’s 5th congressional district in the U.S. House (1975–1985). A Navy jet pilot from 1962 to 1967, he later worked as a congressional aide before winning election to Congress. He won his Senate seat in 1984 and became a prominent liberal voice on labor, health, and disability rights.','Medicine & Health|Defense & Security|Civil Rights & Society',5,'/avatars/184.jpg'),
(185,'broyhillnc','lbn123456','Broyhill (N. C.)','Republican','Conservative','Male','U.S. Senator from North Carolina','University of North Carolina at Chapel Hill','Bachelor','North Carolina','James Thomas Broyhill was a Republican U.S. Representative from North Carolina (1963–1986) who was appointed to the U.S. Senate in 1986 to fill the seat vacated by John P. East. He served briefly until defeated in the Republican primary by Jim Broyhill (actually by Jim Broyhill?); he lost the 1986 GOP primary to Jim Broyhill? (Correction: he lost to Jim Broyhill? )','Governance & Reform',NULL,'/avatars/185.svg'),
(186,'adams','lbn123456','Adams','Democrat','Liberal','Male','U.S. Senator from Washington','Unknown','Unknown','Washington','Brock Adams (1927–2004) was a Democratic U.S. Senator from Washington (1987–1993) and previously served as a U.S. Representative from Washington (1965–1977) and U.S. Secretary of Transportation (1977–1979) under President Jimmy Carter. In the Senate he worked on transportation, labor, and Pacific Northwest issues. He was defeated for reelection in 1992.','Civil Rights & Society',NULL,'/avatars/186.svg'),
(187,'christopherbond','lbn123456','Christopher Bond','Republican','Conservative','Male','U.S. Senator from Missouri','University of Virginia','J.D.','Missouri','Christopher S. “Kit” Bond (1939–2015) was a Missouri Republican who served as governor of Missouri (1973–1977, 1981–1985) and as U.S. Senator from Missouri (1987–2011). Earlier he was Missouri attorney general (1971–1973). In the Senate he focused on transportation, appropriations, and intelligence issues, and became a senior member of the Appropriations Committee.','Economics & Finance|Law & Justice|Defense & Security',39,'/avatars/187.svg'),
(188,'kentconrad','lbn123456','Kent Conrad','Democrat','Moderate','Male','U.S. Senator from North Dakota','Stanford University; George Washington University','J.D.','North Dakota','Kent Conrad (born 1948) served as a Democratic U.S. Senator from North Dakota (1987–2013). He previously represented North Dakota at-large in the U.S. House (1985–1987), was North Dakota Tax Commissioner (1977–1981), and served in the state Senate (1981–1985). In the Senate he was known for budget and fiscal policy work, chairing the Senate Budget Committee.','Economics & Finance',6,'/avatars/188.jpg'),
(189,'thomasdaschle','lbn123456','Thomas Daschle','Democrat','Liberal','Male','U.S. Senator from South Dakota','South Dakota State University; University of South Dakota','J.D.','South Dakota','Tom Daschle served as U.S. Representative for South Dakota’s at-large district (1979–1987) and U.S. Senator (1987–2005). A Democrat, he was Senate Minority Leader (1995–2001, 2003–2005) and Senate Majority Leader (2001–2003). He later worked in policy and health-care advocacy and was nominated to be Secretary of Health and Human Services in 2009 but withdrew.','Medicine & Health',7,'/avatars/189.jpg'),
(190,'fowler','lbn123456','Fowler','Democrat','Centrist','Male','U.S. Senator from Georgia','Emory University; University of Alabama School of Law','J.D.','Georgia','Wyche Fowler Jr. was a Georgia attorney and diplomat who served in Congress as a Democratic U.S. Representative (1975–1987) and U.S. Senator (1987–1993). He previously worked as a legislative aide to Sen. Herman Talmadge. After leaving the Senate, he served as U.S. Ambassador to Saudi Arabia (1996–2001) under President Bill Clinton.','Law & Justice|Foreign Relations',NULL,'/avatars/190.svg'),
(191,'bobgraham','lbn123456','Bob Graham','Democrat','Moderate','Male','U.S. Senator from Florida','University of Florida','J.D.','Florida','Bob Graham (1936–2024) was a Florida Democrat who served as governor of Florida (1979–1987) and then as U.S. senator (1987–2005). In the Senate he focused on intelligence, national security, and government oversight, chairing the Senate Select Committee on Intelligence and later co-chairing the congressional inquiry into the September 11 attacks. Earlier, he served in the Florida House and Senate.','Defense & Security|Governance & Reform',50,'/avatars/191.jpg'),
(192,'barbaramikulski','lbn123456','Barbara Mikulski','Democrat','Liberal','Female','U.S. Senator from Maryland','Mount Saint Agnes College; University of Maryland School of Social Work','Master','Maryland','Barbara A. Mikulski was a Democratic U.S. Senator from Maryland (1987–2017) and previously a U.S. Representative (1977–1987). A former social worker and community organizer, she began her political career on the Baltimore City Council (1971–1976). Elected to the Senate in 1986, she became the first woman elected as U.S. Senator from Maryland and served as a leading appropriator.','Medicine & Health',27,'/avatars/192.jpg'),
(193,'harryreid','lbn123456','Harry Reid','Democrat','Liberal','Male','U.S. Senator from Nevada','Utah State University; George Washington University Law School','J.D.','Nevada','Harry Reid (1939–2021) was a Democratic U.S. Senator from Nevada (1987–2017), previously serving as Nevada’s lieutenant governor (1971–1975) and as a U.S. Representative (1983–1987). A former boxer and attorney, he became Senate Majority Leader (2007–2015) and earlier served as Senate Minority Whip. He played major roles in Democratic legislative strategy and judicial confirmations.','Law & Justice',28,'/avatars/193.jpg'),
(194,'sanford','lbn123456','Sanford','Democrat','Moderate','Male','U.S. Senator from North Carolina','Brevard College; University of North Carolina at Chapel Hill','Bachelor','North Carolina','Terry Sanford (1917–1998) was a North Carolina Democratic politician and educator. He served as governor of North Carolina (1961–1965), promoting public education and racial moderation, and later founded and led Duke University’s Institute of Policy Sciences and Public Affairs. He was appointed to the U.S. Senate in 1986 and served from 1986 to 1993, focusing on education, budget, and government reform.','Education & Science|Governance & Reform|Economics & Finance',NULL,'/avatars/194.svg'),
(195,'wirth','lbn123456','Wirth','Democrat','Liberal','Male','U.S. Senator from Colorado','Princeton University; Harvard Law School','J.D.','Colorado','Timothy E. Wirth (born 1939) is a Colorado Democrat who served in the U.S. House (1975–1987) and U.S. Senate (1987–1993). He later was Under Secretary of State for Global Affairs in the Clinton administration. Wirth became president of the United Nations Foundation (1998–2013) and has been active in environmental and global policy issues.','Foreign Relations|Environment & Energy|Governance & Reform',NULL,'/avatars/195.svg'),
(196,'johnbreaux','lbn123456','John Breaux','Democrat','Moderate','Male','U.S. Senator from Louisiana','University of Southwestern Louisiana; Loyola University New Orleans College of Law','J.D.','Louisiana','John Berlinger Breaux (born 1944) is a Louisiana Democrat who served in the U.S. House (1972–1987) and U.S. Senate (1987–2005). A Southern Democrat associated with the New Democrat Coalition, he was known as one of the party’s more conservative members. After leaving Congress, he became a lobbyist and co-founded the Breaux-Lott Leadership Group.','Governance & Reform',79,'/avatars/196.jpg'),
(197,'karnes','lbn123456','Karnes','Republican','Conservative','Male','U.S. Senator from Nebraska','University of Nebraska–Lincoln; University of Nebraska College of Law','J.D.','Nebraska','David Kemp Karnes was a Republican U.S. Senator from Nebraska, appointed in 1987 and serving until 1989. He was previously an attorney, businessman, and civic leader in Nebraska. After leaving the Senate he worked in law and merchant banking/consulting, including leadership of The Fairmont Group and work with Kutak Rock, and remained active in charitable and educational organizations.','Law & Justice|Economics & Finance|Education & Science',NULL,'/avatars/197.svg'),
(198,'johnmccain','lbn123456','John McCain','Republican','Conservative','Male','U.S. Senator from Arizona','United States Naval Academy','Bachelor','Arizona','John McCain was a Republican U.S. senator from Arizona (1987–2018), previously a U.S. representative (1983–1987). A Naval Academy graduate and Vietnam War POW, he became known for national security and reform issues. He ran for president in 2000 and was the Republican nominee in 2008, losing to Barack Obama. He chaired the Senate Armed Services Committee.','Defense & Security|Governance & Reform',56,'/avatars/198.jpg'),
(199,'richardshelby','lbn123456','Richard Shelby','Democrat (until 1994), Republican (1994-2023)','Conservative','Male','U.S. Senator from Alabama','University of Alabama; University of Alabama School of Law','J.D.','Alabama','Richard C. "Dick" Shelby (born 1934) is an Alabama lawyer and politician. He served in the Alabama State Senate (1971–1979), then as U.S. Representative from Alabama (1979–1987). Elected to the U.S. Senate in 1986 as a Democrat, he switched to the Republican Party in 1994 and served until 2023, becoming Alabama’s longest-serving U.S. senator.','Law & Justice',49,'/avatars/199.jpg'),
(200,'conradburns','lbn123456','Conrad Burns','Republican','Conservative','Male','U.S. Senator from Montana','University of Missouri','Master','Montana','Conrad Ray Burns (1935–2016) was a Republican U.S. Senator from Montana (1989–2007). Before the Senate, he served in the Montana Senate and worked as an agricultural educator and broadcaster. In Congress he served on the Senate Appropriations Committee, chaired its Interior Subcommittee, and led a Communications subcommittee on Commerce, Science, and Transportation. After leaving office, he worked as a lobbyist.','Economics & Finance|Education & Science',42,'/avatars/200.jpg');
INSERT INTO lbn_user (id,username,password,display_name,party,leaning,gender,position,alma_mater,education_level,state,bio,interests,committee_id,avatar) VALUES
(201,'jamesjeffords','lbn123456','James Jeffords','Republican (until 2001), Independent (2001-2007)','Moderate','Male','U.S. Senator from Vermont','Yale University; Harvard Law School','J.D.','Vermont','James M. Jeffords (1934–2014) was a Vermont lawyer and politician. He served in the Vermont Senate (1967–1969) and as Vermont attorney general (1969–1973). Elected to the U.S. House in 1974, he served from 1975 to 1989. He then served as U.S. senator from Vermont (1989–2007), leaving the Republican Party in 2001 to become an independent who caucused with Democrats.','Law & Justice',102,'/avatars/201.svg'),
(202,'trentlott','lbn123456','Trent Lott','Republican','Conservative','Male','U.S. Senator from Mississippi','University of Mississippi','J.D.','Mississippi','Chester Trent Lott Sr. (born 1941) is a Mississippi Republican who served in the U.S. House (1973–1989) and U.S. Senate (1989–2007). He rose to party leadership, serving as Senate Majority Leader (1996–2001, 2003) and Senate Minority Leader (1995–1996, 2001–2003). He resigned as majority leader in 2002 after controversy over comments about Strom Thurmond.','Governance & Reform',57,'/avatars/202.jpg'),
(203,'dancoats','lbn123456','Dan Coats','Republican','Conservative','Male','U.S. Senator from Indiana','Wheaton College; Indiana University School of Law – Indianapolis','J.D.','Indiana','Daniel Ray Coats (born 1943) is a Republican politician from Indiana. He served in the U.S. Army (1966–1968), then represented Indiana’s 4th district in the U.S. House (1981–1989). Appointed to the U.S. Senate in 1989 after Dan Quayle became vice president, he won the 1990 special election and a full term in 1992, serving until 1999. He later was U.S. Ambassador to Germany and Director of National Intelligence.','Defense & Security|Foreign Relations',58,'/avatars/203.jpg'),
(204,'herbertkohl','lbn123456','Herbert Kohl','Democrat','Moderate','Male','U.S. Senator from Wisconsin','University of Wisconsin–Madison, Harvard University','MBA','Wisconsin','Herbert H. Kohl (1935–2023) was a Wisconsin businessman and Democrat who served as U.S. senator from Wisconsin from 1989 to 2013. He previously chaired the Wisconsin Democratic Party and ran his family’s Kohl’s department store business. In 1985 he bought the Milwaukee Bucks to keep the team in Milwaukee. In the Senate he focused on consumer protection, education, and government accountability.','Education & Science|Governance & Reform',29,'/avatars/204.svg'),
(205,'richardbryan','lbn123456','Richard Bryan','Democrat','Moderate','Male','U.S. Senator from Nevada','University of Nevada, Reno; University of California, Hastings College of the Law','J.D.','Nevada','Richard H. Bryan is a Nevada attorney and Democratic politician. He served in the Nevada State Senate, then as Nevada attorney general, and was elected governor (1983–1989). Bryan represented Nevada in the U.S. Senate from 1989 to 2001. After leaving the Senate, he returned to private life and legal work.','Law & Justice',67,'/avatars/205.jpg'),
(206,'charlesrobb','lbn123456','Charles Robb','Democrat','Moderate','Male','U.S. Senator from Virginia','University of Wisconsin–Madison; University of Virginia','J.D.','Virginia','Charles S. "Chuck" Robb is a former U.S. Marine officer and Democratic politician. He served as Governor of Virginia (1982–1986) and as U.S. Senator from Virginia (1989–2001). He is married to Lynda Bird Johnson, daughter of President Lyndon B. Johnson. Robb lost his 2000 Senate reelection bid to Republican George Allen and later co-chaired the Iraq Intelligence Commission.','Defense & Security',51,'/avatars/206.jpg'),
(207,'jkerrey','lbn123456','J. Kerrey','Democrat','Moderate','Male','U.S. Senator from Nebraska','University of Nebraska–Lincoln','Bachelor','Nebraska','Joseph Robert "Bob" Kerrey (born 1943) is a Democrat who served as governor of Nebraska (1983–1987) and U.S. senator from Nebraska (1989–2001). A U.S. Navy SEAL in Vietnam, he received the Medal of Honor and later faced controversy over the Thanh Phong raid. He ran for the 1992 Democratic presidential nomination and later served as president of The New School (2001–2010).','Defense & Security|Education & Science',9,'/avatars/207.svg'),
(208,'conniemack','lbn123456','Connie Mack','Republican','Conservative','Male','U.S. Senator from Florida','University of Florida','Bachelor','Florida','Connie Mack III (born 1940) is a Republican politician who served as a U.S. Senator from Florida (1989–2001). First elected in 1988, he became known for conservative fiscal and national security positions. He previously worked in business and served as president of the Export-Import Bank of the United States (1987–1988) under President Ronald Reagan.','Defense & Security|Economics & Finance',41,'/avatars/208.jpg'),
(209,'josephlieberman','lbn123456','Joseph Lieberman','Democrat (until 2006), Independent (2006-2013; caucused with Democrats)','Moderate','Male','U.S. Senator from Connecticut','Yale University','J.D.','Connecticut','Joseph I. Lieberman (1942–2024) was a U.S. Senator from Connecticut (1989–2013). A Democrat, he later ran as an Independent and caucused with Senate Democrats. He served in the Connecticut State Senate, was Connecticut attorney general (1983–1989), and gained national prominence as Al Gore’s Democratic vice-presidential running mate in 2000. He was re-elected to the Senate in 1994, 2000, and 2006.','Law & Justice',52,'/avatars/209.jpg'),
(210,'danielakaka','lbn123456','Daniel Akaka','Democrat','Unknown','Unknown','Unknown','Unknown','Unknown','','Information unavailable.','Governance & Reform',86,'/avatars/210.jpg'),
(211,'quentinnburdick','lbn123456','Quentin N. Burdick','Democrat','Liberal','Male','U.S. Senator from North Dakota','University of Minnesota; University of Minnesota Law School','J.D.','North Dakota','Quentin N. Burdick was a North Dakota lawyer and North Dakota Democratic–NPL politician. He served in the U.S. House of Representatives (1959–1960) and then in the U.S. Senate (1960–1992), representing North Dakota for over three decades. He chaired the Senate Environment and Public Works Committee and was among the Senate’s longest-serving members at his death in 1992.','Law & Justice|Environment & Energy',NULL,'/avatars/211.jpg'),
(212,'hankbrown','lbn123456','Hank Brown','Republican','Conservative','Male','U.S. Representative from Ohio''s 7th district','Ohio State University','Bachelor','Ohio','Clarence James “Bud” Brown Jr. (1927–2022) was a Republican from Ohio. He served in the U.S. House of Representatives for Ohio’s 7th district from 1965 to 1983. After leaving Congress, he joined the Reagan administration as Deputy Secretary of Commerce and served as Acting Secretary of Commerce. He was also a newspaper publisher.','Economics & Finance|Governance & Reform',74,'/avatars/212.jpg'),
(213,'larrycraig','lbn123456','Larry Craig','Republican','Conservative','Male','U.S. Senator from Idaho','University of Idaho','Bachelor','Idaho','Larry Craig is a Republican politician from Idaho. He served as U.S. Representative for Idaho’s 1st district (1981–1991) and as U.S. Senator from Idaho (1991–2009). Raised on a ranch in Washington County, he earned a BA in political science from the University of Idaho and previously served in the Idaho Senate (1974–1980).','Education & Science',16,'/avatars/213.jpg'),
(214,'robertsmith','lbn123456','Robert Smith','Republican','Unknown','Male','Unknown','Unknown','Unknown','','The provided reference text does not identify a specific U.S. Senator or Representative named R.C. Smith. Multiple individuals could match this abbreviated name, and there is insufficient information to reliably determine the correct Congress member, office held, education, or biography from the dataset details given.','Education & Science',59,'/avatars/214.svg'),
(215,'paulwellstone','lbn123456','Paul Wellstone','Democrat (DFL)','Progressive','Male','U.S. Senator from Minnesota','University of North Carolina at Chapel Hill','PhD','Minnesota','Paul D. Wellstone (1944–2002) was a Democratic–Farmer–Labor U.S. Senator from Minnesota (1991–2002). An academic and political science professor at Carleton College, he won election in 1990 and became a prominent progressive and populist voice in the Senate. He was killed in a plane crash near Eveleth, Minnesota, days before the 2002 election.','Education & Science|Agriculture & Rural|Civil Rights & Society',87,'/avatars/215.jpg'),
(216,'johnseymour','lbn123456','John Seymour','Republican','Conservative','Male','U.S. Senator from California','University of Santa Clara','Bachelor','California','John F. Seymour Jr. is a California Republican who served as a U.S. senator from 1991 to 1992, appointed to fill the vacancy created when Pete Wilson became governor. He previously served in local and regional government in Orange County, including on the Orange County Board of Supervisors. Seymour ran in the 1992 special election to complete the term but lost to Democrat Dianne Feinstein.','Governance & Reform',NULL,'/avatars/216.svg'),
(217,'harriswofford','lbn123456','Harris Wofford','Democrat','Liberal','Male','U.S. Senator from Pennsylvania','University of Chicago; Yale University; Howard University School of Law','J.D.','Pennsylvania','Harris Wofford was a Democratic U.S. Senator from Pennsylvania (1991–1995), elected in a 1991 special election after John Heinz’s death. A lawyer and civil rights activist, he worked with John F. Kennedy and Lyndon B. Johnson on civil rights and anti-poverty efforts. He later served as president of Bryn Mawr College (1970–1978) and as Pennsylvania Secretary of Labor and Industry (1987–1991).','Civil Rights & Society|Law & Justice',94,'/avatars/217.jpg'),
(218,'barbaraboxer','lbn123456','Barbara Boxer','Democrat','Liberal','Female','U.S. Senator from California','Brooklyn College; Golden Gate University School of Law','J.D.','California','Barbara Boxer (born 1940) served as a U.S. Representative from California (1983–1993) and U.S. Senator from California (1993–2017). Before Congress she was a Marin County supervisor and worked as a journalist. In the Senate she focused on environmental protection, transportation, public works, and women’s health, and chaired the Senate Environment and Public Works Committee (2015–2017).','Environment & Energy|Medicine & Health',68,'/avatars/218.jpg'),
(219,'carolmoseleybraun','lbn123456','Carol Moseley-Braun','Democrat','Liberal','Female','U.S. Senator from Illinois','University of Illinois Urbana-Champaign; University of Chicago','J.D.','Illinois','Carol Moseley-Braun (born 1947) is a Democratic politician and diplomat. She served in the Illinois House (1979–1988) and as Cook County Recorder of Deeds (1988–1992). Elected U.S. Senator from Illinois (1993–1999), she was the first African-American woman in the Senate and the first female U.S. senator from Illinois. Defeated in 1998, she later served as U.S. ambassador to New Zealand and Samoa (1999–2001).','Foreign Relations',70,'/avatars/219.jpg'),
(220,'robertfbennett','lbn123456','Robert F. Bennett','Republican','Conservative','Male','U.S. Senator from Utah','Brigham Young University, Harvard Business School','Master','Utah','Robert F. Bennett (1933–2016) was a Republican U.S. senator from Utah, serving 1993–2011. A businessman and political aide before entering the Senate, he became a senior member of committees including Appropriations, Banking, Rules, Energy, and the Joint Economic Committee. Long viewed as a reliable conservative, he lost renomination in 2010 amid Tea Party opposition.','Economics & Finance|Environment & Energy',NULL,'/avatars/220.jpg'),
(221,'dirkkempthorne','lbn123456','Dirk Kempthorne','Republican','Conservative','Male','U.S. Senator from Idaho','San Diego State University; University of Idaho','Bachelor','Idaho','Dirk Kempthorne (born 1951) is a Republican politician from Idaho. He served as mayor of Boise (1986–1993), then as U.S. senator from Idaho (1993–1999). He was elected governor of Idaho, serving from 1999 to 2006. Kempthorne became U.S. secretary of the interior under President George W. Bush (2006–2009) and later led the American Council of Life Insurers.','Governance & Reform',60,'/avatars/221.jpg'),
(222,'lauchfaircloth','lbn123456','Lauch Faircloth','Republican (1991-1999), Democrat (before 1991)','Conservative','Male','U.S. Senator from North Carolina','North Carolina State University','Bachelor','North Carolina','Lauch Faircloth (1928–2023) was a North Carolina politician who served one term as a Republican U.S. senator (1993–1999). Long active as a Democrat, he worked as a political consultant and held state posts including chairman of the North Carolina Highway Commission (1969–1973) and Secretary of Commerce. He switched to the Republican Party in 1991 and defeated Democratic incumbent Terry Sanford in 1992.','Economics & Finance',61,'/avatars/222.jpg'),
(223,'juddgregg','lbn123456','Judd Gregg','Republican','Conservative','Male','U.S. Senator from New Hampshire','Columbia University; Georgetown University Law Center','J.D.','New Hampshire','Judd Gregg served as a U.S. Senator from New Hampshire (1993–2011). He previously served in the U.S. House (1981–1989) and as Governor of New Hampshire (1989–1993). A Republican, he was known for fiscal and budget policy work, including as chair of the Senate Budget Committee. After leaving the Senate, he worked in the private sector and served on public-policy boards.','Economics & Finance',75,'/avatars/223.jpg'),
(224,'bencampbell','lbn123456','Ben Campbell','Democrat','Moderate','Male','U.S. Senator from Colorado','Metropolitan State College of Denver','Bachelor','Colorado','Ben Nighthorse Campbell served as a U.S. Senator from Colorado (1993–2005). A former Olympic judoka and jewelry businessman, he previously served in the U.S. House representing Colorado (1987–1993). In the Senate he focused on Native American affairs and chaired the Senate Committee on Indian Affairs. He was elected as a Democrat but later switched parties.','Governance & Reform',69,'/avatars/224.svg'),
(225,'byrondorgan','lbn123456','Byron Dorgan','Democrat','Liberal','Male','U.S. Senator from North Dakota','University of North Dakota','Bachelor','North Dakota','Byron L. Dorgan served North Dakota in Congress as a U.S. Representative (1981–1992) and U.S. Senator (1992–2011). A Democrat, he previously worked in state government and served as North Dakota tax commissioner. In the Senate he held leadership roles, chaired the Democratic Policy Committee, and led the Senate Committee on Indian Affairs. He announced in 2010 he would not seek re-election.','Economics & Finance|Governance & Reform',80,'/avatars/225.jpg'),
(226,'russelfeingold','lbn123456','Russel Feingold','Democrat','Liberal','Male','U.S. Senator from Wisconsin','University of Wisconsin–Madison; Magdalen College, Oxford; Harvard Law School','J.D.','Wisconsin','Russell D. Feingold (born 1953) is a Democratic politician and lawyer who served as U.S. Senator from Wisconsin (1993–2011) after serving in the Wisconsin State Senate (1983–1993). With John McCain, he coauthored the Bipartisan Campaign Reform Act of 2002 and received the 1999 Profile in Courage Award. He was the only senator to vote against the 2001 Patriot Act and lost reelection in 2010.','Governance & Reform|Law & Justice|Defense & Security',10,'/avatars/226.svg'),
(227,'diannefeinstein','lbn123456','Dianne Feinstein','Democrat','Moderate','Female','U.S. Senator from California','Stanford University','Bachelor','California','Dianne Feinstein (1933–2023) was a Democratic U.S. senator from California, serving from 1992 until her death. A longtime San Francisco leader, she served on the city’s Board of Supervisors and became mayor in 1978 after the assassinations of George Moscone and Harvey Milk, holding the office until 1988. In the Senate, she became a senior figure and chaired the Intelligence Committee.','Defense & Security',31,'/avatars/227.jpg'),
(228,'bobkrueger','lbn123456','Bob Krueger','Democrat','Moderate','Male','U.S. Senator from Texas','Rice University; Duke University','PhD','Texas','Robert C. Krueger was a Texas Democrat who served briefly in the U.S. House (1975) and later as a U.S. Senator from Texas (1993), appointed to fill the vacancy after Lloyd Bentsen joined the Clinton administration. He previously served in the Texas Senate and ran unsuccessfully for the 1994 Democratic Senate nomination. Krueger later served as U.S. Ambassador to Burundi (1994–1996).','Foreign Relations|Governance & Reform',84,'/avatars/228.jpg'),
(229,'pattymurray','lbn123456','Patty Murray','Democrat','Liberal','Female','U.S. Senator from Washington','Washington State University','Bachelor','Washington','Patty Murray is a Democratic U.S. senator from Washington, serving since 1993 and the state’s first female senator. Raised in Bothell, she earned a B.A. in physical education from Washington State University and worked as a preschool and parenting teacher. She entered politics via a local school board, then served in the Washington State Senate (1989–1993). She was Senate president pro tempore from 2023 to 2025.','Education & Science',30,'/avatars/229.jpg'),
(230,'paulcoverdell','lbn123456','Paul Coverdell','Republican','Conservative','Male','U.S. Senator from Georgia','University of Georgia','Bachelor','Georgia','Paul Douglas Coverdell (1939–2000) was a Republican U.S. senator from Georgia, serving from 1993 until his death. Before the Senate, he was director of the Peace Corps (1989–1991) under President George H. W. Bush. He also served in the Georgia State Senate and worked in business and civic roles. He was known for foreign policy and public service initiatives.','Foreign Relations',17,'/avatars/230.jpg'),
(231,'kayhutchison','lbn123456','Kay Hutchison','Republican','Conservative','Female','U.S. Senator from Texas','University of Texas at Austin','J.D.','Texas','Kay Bailey Hutchison (born 1943) is a Texas Republican who served as a U.S. Senator from Texas (1993–2013), first elected in a 1993 special election and later re-elected three times. Earlier she served in the Texas House (1972–1976) and as Texas State Treasurer (1991–1993). She later served as U.S. Permanent Representative to NATO (2017–2021).','Governance & Reform',62,'/avatars/231.jpg'),
(232,'harlanmathews','lbn123456','Harlan Mathews','Democrat','Moderate','Male','U.S. Senator from Tennessee (appointed, interim)','University of Tennessee','Bachelor','Tennessee','Harlan Mathews (1927–2014) was a Tennessee Democratic politician appointed to the U.S. Senate (1993–1994) to fill Al Gore’s seat after Gore became vice president. A longtime state official, he served in Tennessee government for decades, including in the state legislature and executive posts such as commissioner of finance and administration and commissioner of transportation, before returning to private life.','Governance & Reform|Economics & Finance',88,'/avatars/232.jpg'),
(233,'spencerabraham','lbn123456','Spencer Abraham','Republican','Conservative','Male','U.S. Senator from Michigan','Michigan State University; Harvard University','J.D.','Michigan','Spencer Abraham (born 1952) is a Republican attorney and politician who served as U.S. Senator from Michigan (1995–2001). He later served as the 10th U.S. Secretary of Energy (2001–2005) under President George W. Bush. He is a founder of the Federalist Society and co-founded the Harvard Journal of Law & Public Policy.','Law & Justice|Environment & Energy',111,'/avatars/233.svg'),
(234,'johnashcroft','lbn123456','John Ashcroft','Republican','Conservative','Male','U.S. Senator from Missouri','Yale University; University of Chicago Law School','J.D.','Missouri','John Ashcroft (born 1942) is a Missouri Republican who served as U.S. Senator from Missouri (1995–2001). He previously held statewide office as Missouri state auditor (1973–1975), attorney general (1976–1985), and governor (1985–1993). Ashcroft later served as U.S. attorney general under President George W. Bush (2001–2005) and afterward worked as a lobbyist and founded The Ashcroft Group.','Law & Justice|Defense & Security',113,'/avatars/234.svg'),
(235,'michaeldewine','lbn123456','Michael DeWine','Republican','Conservative','Male','U.S. Senator from Ohio','Miami University; Ohio Northern University College of Law','J.D.','Ohio','Mike DeWine is an Ohio Republican politician and attorney. He served in the U.S. House (1983–1991) and the U.S. Senate (1995–2007). He was Ohio’s lieutenant governor (1991–1994), Ohio attorney general (2011–2019), and became governor of Ohio in 2019. Born in Yellow Springs, he earned a BA from Miami University and a JD from Ohio Northern University.','Law & Justice|Education & Science',117,'/avatars/235.jpg'),
(236,'williamfrist','lbn123456','William Frist','Republican','Conservative','Male','U.S. Senator from Tennessee','Princeton University; Harvard Medical School','M.D.','Tennessee','Bill Frist (born 1952) is a Republican physician and former U.S. Senator from Tennessee (1995–2007). A cardiothoracic transplant surgeon, he founded the Vanderbilt Transplant Center before entering politics. He defeated incumbent Jim Sasser in 1994, later chaired the National Republican Senatorial Committee, and served as Senate Majority Leader (2003–2007), helping advance parts of President George W. Bush’s domestic agenda.','Medicine & Health',109,'/avatars/236.jpg'),
(237,'rodgrams','lbn123456','Rod Grams','Republican','Conservative','Male','U.S. Senator from Minnesota','University of Minnesota','Bachelor','Minnesota','Rod Grams (1948–2013) was a Minnesota television news anchor turned politician. After working as a senior anchor at KMSP-TV, he was elected to the U.S. House in 1992 from Minnesota’s 6th district. He then won election to the U.S. Senate in 1994, serving one term (1995–2001) before losing reelection to Mark Dayton in 2000.','Governance & Reform',108,'/avatars/237.jpg'),
(238,'jamesinhofe','lbn123456','James Inhofe','Republican','Conservative','Male','U.S. Senator from Oklahoma','University of Tulsa','Bachelor','Oklahoma','James M. Inhofe (1934–2024) was a Republican politician who served as U.S. senator from Oklahoma (1994–2023), the state’s longest-serving senator. He previously served as U.S. representative for Oklahoma’s 1st district (1987–1994) and in Oklahoma state and local offices. In the Senate he became a leading conservative voice on defense and environmental policy, including chairing the Senate Armed Services Committee.','Defense & Security|Environment & Energy',106,'/avatars/238.svg'),
(239,'jonkyl','lbn123456','Jon Kyl','Republican','Conservative','Male','U.S. Senator from Arizona','University of Arizona','J.D.','Arizona','Jon Kyl is a Republican politician and lobbyist who served as U.S. Representative from Arizona (1987–1995) and U.S. Senator from Arizona (1995–2013). He was Senate Minority Whip from 2007 to 2013. After retiring, he worked as a lobbyist. He briefly returned to the Senate in 2018 after John McCain’s death, serving until early 2019.','Governance & Reform',115,'/avatars/239.jpg'),
(240,'ricksantorum','lbn123456','Rick Santorum','Republican','Conservative','Male','U.S. Senator from Pennsylvania','Pennsylvania State University; University of Pittsburgh','J.D.','Pennsylvania','Rick Santorum is a Republican politician who served as U.S. Representative from Pennsylvania’s 18th district (1991–1995) and U.S. Senator from Pennsylvania (1995–2007). He rose to Senate Republican leadership as conference chair and was known for strong social conservative positions. He lost reelection in 2006 to Bob Casey Jr. Santorum later ran for the 2012 Republican presidential nomination.','Governance & Reform',103,'/avatars/240.jpg'),
(241,'richardshelby1','lbn123456','Richard Shelby','Democrat (1987-1994), Republican (1994-2023)','Conservative','Male','U.S. Senator from Alabama','University of Alabama; University of Alabama School of Law','J.D.','Alabama','Richard C. Shelby (born 1934) served as U.S. senator from Alabama (1987–2023). Elected in 1986 as a Democrat, he switched to the Republican Party in 1994. Previously he was a Tuscaloosa city prosecutor, a U.S. magistrate, and served in the Alabama State Senate (1971–1978) and the U.S. House (1979–1987).','Law & Justice',49,'/avatars/241.jpg'),
(242,'olympiasnowe','lbn123456','Olympia Snowe','Republican','Moderate','Female','U.S. Senator from Maine','University of Maine','Bachelor','Maine','Olympia J. Snowe is a Maine Republican who served in Congress for decades, including as U.S. Representative from Maine (1979–1995) and U.S. Senator (1995–2013). Known as a centrist, she often influenced close Senate votes and helped broker bipartisan agreements. She announced in 2012 she would not seek reelection, citing increasing partisanship, and left office in 2013.','Governance & Reform',110,'/avatars/242.jpg'),
(243,'craigthomas','lbn123456','Craig Thomas','Republican','Conservative','Male','U.S. Senator from Wyoming','University of Wyoming','Bachelor','Wyoming','Craig Lyle Thomas (1933–2007) was a Republican U.S. Senator from Wyoming (1995–2007). He previously served as Wyoming’s at-large U.S. Representative after winning a 1989 special election, and later won reelection. Before Congress, he worked in agriculture and rural development, including leadership with the Wyoming Farm Bureau and service in the Wyoming House of Representatives (1984–1989). He was known for agriculture and rural policy expertise.','Agriculture & Rural',114,'/avatars/243.svg'),
(244,'fredthompson','lbn123456','Fred Thompson','Republican','Conservative','Male','U.S. Senator from Tennessee','Memphis State University, Vanderbilt University','J.D.','Tennessee','Fred Dalton Thompson (1942–2015) was a Republican U.S. Senator from Tennessee (1994–2003), appointed to fill Al Gore’s former seat and later elected. A lawyer and former counsel to the Senate Watergate Committee, he also worked as a lobbyist and became a nationally known actor. He ran unsuccessfully for the 2008 Republican presidential nomination.','Law & Justice|Environment & Energy',116,'/avatars/244.jpg'),
(245,'sheilafrahm','lbn123456','Sheila Frahm','Republican','Conservative','Female','U.S. Senator from Kansas','Unknown','Unknown','Kansas','Sheila Frahm (born 1945) is a Kansas Republican politician who briefly served in the U.S. Senate in 1996 after being appointed to fill the vacancy created by Sen. Nancy Kassebaum’s resignation. She later ran in the 1996 special election to complete the term but lost the Republican primary to Sam Brownback. She was previously active in Kansas state and local public service.','Governance & Reform',107,'/avatars/245.jpg'),
(246,'ronwyden','lbn123456','Ron Wyden','Democrat','Liberal','Male','U.S. Senator from Oregon','Stanford University; University of California, Santa Barbara','Bachelor','Oregon','Ron Wyden is a Democratic U.S. senator from Oregon, first elected in a 1996 special election and serving continuously since. He previously represented Oregon in the U.S. House (1981–1996). In the Senate he has been a leading voice on tax and health policy and is known for privacy and civil-liberties advocacy, including opposition to expansive government surveillance. He has chaired major committees, including Senate Finance.','Economics & Finance|Medicine & Health|Governance & Reform',112,'/avatars/246.jpg'),
(247,'wayneallard','lbn123456','Wayne Allard','Republican','Conservative','Male','U.S. Senator from Colorado','Colorado State University','D.V.M.','Colorado','Alan Wayne Allard (born 1943) is a Republican politician and veterinarian from Colorado. He served in the Colorado State Senate (1983–1991), the U.S. House representing Colorado’s 4th district (1991–1997), and the U.S. Senate (1997–2009). He did not seek re-election in 2008 and later worked as a Washington lobbyist.','Governance & Reform',138,'/avatars/247.jpg'),
(248,'chuckhagel','lbn123456','Chuck Hagel','Republican','Conservative','Male','U.S. Senator from Nebraska','University of Nebraska at Omaha','Bachelor','Nebraska','Chuck Hagel is an American politician and Vietnam War veteran who served as U.S. Senator from Nebraska (1997–2009). A Republican, he was elected in 1996 and reelected in 2002, then chose not to run in 2008. After the Senate, he served as chair of the President’s Intelligence Advisory Board (2009–2013) and as U.S. Secretary of Defense (2013–2015).','Defense & Security',140,'/avatars/248.svg'),
(249,'timhutchinson','lbn123456','Tim Hutchinson','Republican','Conservative','Male','U.S. Senator from Arkansas','Bob Jones University; University of Arkansas','Bachelor','Arkansas','Tim Hutchinson (born 1949) is a Republican politician and lobbyist from Arkansas. He served as U.S. Representative for Arkansas''s 3rd district (1993–1997) and then as U.S. Senator from Arkansas (1997–2003), the first Arkansas Republican senator since Reconstruction. He lost reelection in 2002 to Mark Pryor. After leaving the Senate, he worked as a lobbyist.','Governance & Reform',145,'/avatars/249.jpg'),
(250,'michaelenzi','lbn123456','Michael Enzi','Republican','Conservative','Male','U.S. Senator from Wyoming','George Washington University; University of Denver','Bachelor','Wyoming','Michael B. Enzi was a Republican U.S. Senator from Wyoming (1997–2021). An Air Force/Air National Guard veteran, he previously served as mayor of Gillette, in the Wyoming House of Representatives (from 1987), and in the Wyoming Senate. In Washington he focused on fiscal policy, health and education issues, and served on major Senate committees. He was among Wyoming’s longest-serving senators.','Medicine & Health|Defense & Security|Economics & Finance',139,'/avatars/250.jpg'),
(251,'patroberts','lbn123456','Pat Roberts','Republican','Conservative','Male','U.S. Senator from Kansas','Kansas State University; University of Kansas','J.D.','Kansas','Pat Roberts is a Republican who served Kansas in Congress. He was a U.S. Representative from Kansas (1981–1997) before serving as U.S. Senator (1997–2023). A former aide to Rep. Keith Sebelius, he became known for agricultural policy and chaired the Senate Agriculture Committee, as well as the Senate Intelligence Committee (2015–2020).','Defense & Security|Agriculture & Rural',134,'/avatars/251.svg'),
(252,'jeffsessions','lbn123456','Jeff Sessions','Republican','Conservative','Male','U.S. Senator from Alabama','Huntingdon College; University of Alabama','J.D.','Alabama','Jeff Sessions (born 1946) is an Alabama Republican. He served as U.S. Attorney for the Southern District of Alabama (1981–1993), then Alabama attorney general (1995–1997) and U.S. senator from Alabama (1997–2017). He resigned from the Senate to become U.S. attorney general (2017–2018) in the Trump administration.','Law & Justice|Governance & Reform',146,'/avatars/252.svg'),
(253,'samuelbrownback','lbn123456','Samuel Brownback','Republican','Conservative','Male','U.S. Senator from Kansas','Kansas State University; University of Kansas','J.D.','Kansas','Samuel Dale Brownback (born 1956) is a Kansas Republican. He served as U.S. Representative for Kansas’s 2nd district (1995–1996) and U.S. Senator from Kansas (1996–2011). After leaving the Senate, he was governor of Kansas (2011–2018) and later served as U.S. Ambassador-at-Large for International Religious Freedom (2018–2021). He ran for the 2008 Republican presidential nomination.','Foreign Relations',144,'/avatars/253.jpg'),
(254,'richarddurbin','lbn123456','Richard Durbin','Democrat','Liberal','Male','U.S. Senator from Illinois','Georgetown University (School of Foreign Service); Georgetown University Law Center','J.D.','Illinois','Richard J. Durbin is a Democratic politician and attorney from Illinois. He served in the U.S. House of Representatives (1983–1997) before becoming U.S. senator in 1997. He has been Senate Democratic Whip since 2005, serving as the party’s No. 2 leader, and chaired the Senate Judiciary Committee (2021–2025).','Law & Justice',143,'/avatars/254.svg'),
(255,'timjohnson','lbn123456','Tim Johnson','Democrat','Liberal','Male','U.S. Senator from South Dakota','Grinnell College; University of Minnesota','PhD','South Dakota','Thomas Francis “Tom” Johnson (1894–1969) was a Democratic U.S. Senator from South Dakota (1949–1963). A former University of Minnesota economics professor and WWII-era federal official, he was elected to the Senate in 1948 and served until retiring in 1963. He was succeeded by George McGovern.','Economics & Finance|Education & Science',136,'/avatars/255.svg'),
(256,'roberttorricelli','lbn123456','Robert Torricelli','Democrat','Liberal','Male','U.S. Senator from New Jersey','Rutgers University; Georgetown University Law Center','J.D.','New Jersey','Robert G. Torricelli (born 1951) is a New Jersey Democrat who served in the U.S. House (1983–1997) and U.S. Senate (1997–2003). He chaired the Democratic Senatorial Campaign Committee. In 2002 he ended his re-election campaign after an ethics admonishment tied to campaign finance issues. After leaving Congress, he worked in consulting and real estate.','Governance & Reform|Economics & Finance',148,'/avatars/256.jpg'),
(257,'susancollins','lbn123456','Susan Collins','Republican','Moderate','Female','U.S. Senator from Maine','St. Lawrence University','Bachelor','Maine','Susan M. Collins (born 1952) is a Republican U.S. senator from Maine, serving since 1997. Raised in Caribou, Maine, she graduated from St. Lawrence University. She began her career as a staff assistant to Senator William Cohen, later serving as staff director for a Senate Governmental Affairs subcommittee. She also served in Maine state government, including as commissioner of the Department of Professional and Financial Regulation.','Governance & Reform|Law & Justice|Medicine & Health',147,'/avatars/257.jpg'),
(258,'jackreed','lbn123456','Jack Reed','Democrat','Liberal','Male','U.S. Senator from Rhode Island','United States Military Academy; Harvard University; Harvard Law School','J.D.','Rhode Island','John F. Reed (born 1949) is a Democratic politician and former U.S. Army officer from Rhode Island. He served as U.S. Representative for Rhode Island’s 2nd district (1991–1997) before being elected to the U.S. Senate in 1996. A West Point and Harvard graduate with a Harvard Law J.D., he has focused heavily on defense and appropriations issues.','Defense & Security|Law & Justice|Economics & Finance',141,'/avatars/258.svg'),
(259,'bencampbell1','lbn123456','Ben Campbell','Republican (1995-2005), Democrat (before 1995)','Conservative','Male','U.S. Senator from Colorado','Unknown','Unknown','Colorado','Ben Nighthorse Campbell (1933–2025) was a U.S. Air Force veteran and Cheyenne leader who served Colorado in Congress. He represented Colorado’s 3rd district in the U.S. House (1987–1993) and served as U.S. Senator from Colorado (1993–2005). Elected as a Democrat, he switched to the Republican Party in 1995 and was reelected in 1998. He retired in 2005.','Defense & Security',69,'/avatars/259.svg'),
(260,'maxcleland','lbn123456','Max Cleland','Democrat','Moderate','Male','U.S. Senator from Georgia','Stetson University','Bachelor','Georgia','Joseph Maxwell Cleland was a Georgia Democrat and decorated Vietnam War veteran who lost three limbs in combat. He served in the Georgia State Senate (1971–1975), was Administrator of Veterans Affairs under President Jimmy Carter (1977–1981), and Georgia Secretary of State (1982–1996). Cleland represented Georgia in the U.S. Senate from 1997 to 2003, then held federal appointments including Export-Import Bank director and American Battle Monuments Commission.','Defense & Security',137,'/avatars/260.jpg'),
(261,'marylandrieu','lbn123456','Mary Landrieu','Democrat','Moderate','Female','U.S. Senator from Louisiana','Louisiana State University','J.D.','Louisiana','Mary Landrieu (born 1955) is a Louisiana Democrat who served in the Louisiana House (1980–1988) and as state treasurer (1988–1996). She was U.S. senator from Louisiana (1997–2015), known for post–Hurricane Katrina advocacy and for chairing the Senate Small Business and Entrepreneurship Committee (2009–2014) and the Senate Energy and Natural Resources Committee (2014–2015).','Environment & Energy',135,'/avatars/261.jpg'),
(262,'robertsmith1','lbn123456','Robert Smith','Republican','Conservative','Male','U.S. Senator from Oregon','Brigham Young University; Southwestern University School of Law','J.D.','Oregon','Gordon H. Smith (born 1952) is an Oregon politician and businessman who served as a Republican U.S. Senator from Oregon (1997–2009). Before the Senate he served in the Oregon State Senate and as president and CEO of the Smith Frozen Foods company. After leaving office, he became president of the National Association of Broadcasters (2009–2022) and later held leadership roles in the LDS Church.','Agriculture & Rural',59,'/avatars/262.svg'),
(263,'charlesschumer','lbn123456','Charles Schumer','Democrat','Liberal','Male','U.S. Senator from New York','Harvard College; Harvard Law School','J.D.','New York','Charles E. Schumer (born 1950) is a Democrat serving as U.S. senator from New York since 1999. A Brooklyn native, he previously served in the New York State Assembly (1975–1980) and in the U.S. House of Representatives (1981–1999), representing Brooklyn-based districts. He became Senate Democratic leader in 2017 and served as Senate Majority Leader (2021–2025).','Governance & Reform',154,'/avatars/263.jpg'),
(264,'michaelcrapo','lbn123456','Michael Crapo','Republican','Conservative','Male','U.S. Senator from Idaho','Brigham Young University; Harvard Law School','J.D.','Idaho','Michael D. Crapo (born 1951) is a Republican U.S. senator from Idaho, serving since 1999. He previously represented Idaho’s 2nd congressional district in the U.S. House (1993–1999). Before Congress he served in the Idaho Senate (1984–1992), including as president pro tempore. A lawyer, he graduated from Brigham Young University and Harvard Law School.','Law & Justice|Education & Science',153,'/avatars/264.jpg'),
(265,'peterfitzgerald','lbn123456','Peter Fitzgerald','Republican','Conservative','Male','U.S. Senator from Illinois','Amherst College; Harvard Law School','J.D.','Illinois','Peter Gosselin Fitzgerald (born 1960) is a retired lawyer and Republican politician. He served in the Illinois State Senate (1993–1998) and then as U.S. senator from Illinois (1999–2005), after defeating incumbent Carol Moseley Braun in 1998. Known as a maverick, he declined to seek reelection and was succeeded by Barack Obama. After leaving politics, he co-founded Chain Bridge Bank.','Law & Justice',149,'/avatars/265.svg'),
(266,'blanchemlambert','lbn123456','Blanche M. Lambert','Democrat','Moderate','Female','U.S. Senator from Arkansas','University of Arkansas','Bachelor','Arkansas','Blanche Lambert Lincoln (born 1960) is an Arkansas Democrat who served in the U.S. House representing Arkansas’s 1st district (1993–1997) and in the U.S. Senate (1999–2011). Elected to the Senate in 1998, she became the first woman elected U.S. senator from Arkansas since 1932. She chaired the Senate Agriculture Committee and lost her 2010 reelection bid to Republican John Boozman.','Agriculture & Rural',NULL,'/avatars/266.svg'),
(267,'evanbayh1','lbn123456','Evan Bayh','Democrat','Moderate','Male','U.S. Senator from Indiana','Indiana University Bloomington; University of Virginia','J.D.','Indiana','Birch Evans “Evan” Bayh III (born 1955) is an Indiana Democrat who served as U.S. Senator from Indiana (1999–2011). Previously, he was Indiana secretary of state (1987–1989) and the 46th governor of Indiana (1989–1997). Son of Senator Birch Bayh, he was elected to the Senate in 1998 and reelected in 2004, then announced in 2010 he would not seek reelection.','Governance & Reform',155,'/avatars/267.jpg'),
(268,'jamesbunning','lbn123456','James Bunning','Republican','Conservative','Male','U.S. Senator from Kentucky','Xavier University','Bachelor','Kentucky','Jim Bunning (1931–2017) was a Kentucky Republican who served in the U.S. House (1987–1999) and U.S. Senate (1999–2011). Before politics he was a Major League Baseball pitcher (1955–1971), throwing a 1964 perfect game for the Philadelphia Phillies, and was elected to the National Baseball Hall of Fame. In Congress he was known as a fiscal conservative.','Economics & Finance',152,'/avatars/268.svg'),
(269,'johnchafee1','lbn123456','John Chafee','Republican (to 2007), Independent (2007-2013), Democrat (2013-2019), Libertarian (2019-present)','Moderate','Male','U.S. Senator from Rhode Island','Brown University, Montana State University','Bachelor','Rhode Island','Lincoln D. Chafee (born 1953) is a Rhode Island politician who served as U.S. Senator (1999–2007), appointed after his father John Chafee’s death and elected in 2000. He previously was mayor of Warwick (1993–1999). After leaving the Senate, he served as Rhode Island’s governor (2011–2015). He later changed party affiliation from Republican to independent, then Democrat, and became a Libertarian.','Defense & Security',95,'/avatars/269.svg'),
(270,'johnedwards','lbn123456','John Edwards','Democrat','Liberal','Male','U.S. Senator from North Carolina','North Carolina State University; University of North Carolina at Chapel Hill','J.D.','North Carolina','John Edwards (born 1953) is an American lawyer and former U.S. Senator from North Carolina (1999–2005). Elected in 1998, he defeated Republican incumbent Lauch Faircloth. Edwards ran for the Democratic presidential nomination in 2004 and 2008 and was the 2004 Democratic vice-presidential nominee on John Kerry’s ticket. He declined to seek Senate re-election in 2004.','Defense & Security|Law & Justice',156,'/avatars/270.jpg'),
(271,'georgevoinovich','lbn123456','George Voinovich','Republican','Conservative','Male','U.S. Senator from Ohio','Ohio University; Case Western Reserve University','J.D.','Ohio','George V. Voinovich (1936–2016) was a Republican politician who served as U.S. senator from Ohio (1999–2011). He previously was mayor of Cleveland (1980–1989) and governor of Ohio (1991–1998). Earlier he served as Ohio state auditor and in other state and local roles. He was known as a pragmatic, business-oriented Republican and spent over four decades in public service.','Governance & Reform',151,'/avatars/271.svg'),
(272,'zellmiller','lbn123456','Zell Miller','Democrat','Conservative','Male','U.S. Senator from Georgia','University of Georgia','Master','Georgia','Zell Bryan Miller (1932–2018) was a Georgia Democrat who served as lieutenant governor (1975–1991), governor (1991–1999), and U.S. senator from Georgia (2000–2005), appointed after Paul Coverdell’s death and later elected. As a senator he was a conservative Democrat and notably endorsed Republican George W. Bush in 2004. He did not seek reelection.','Governance & Reform',158,'/avatars/272.jpg'),
(273,'jeancarnahan','lbn123456','Jean Carnahan','Democrat','Moderate','Female','U.S. Senator from Missouri','George Washington University','Bachelor','Missouri','Jean Carnahan was a Missouri Democrat and former first lady of Missouri (1993–2000). After her husband, Gov. Mel Carnahan, died shortly before the 2000 election but won Missouri’s U.S. Senate race posthumously, she was appointed to the seat and served as Missouri’s junior U.S. senator from 2001 to 2002. She later worked as a writer and remained active in public affairs.','Governance & Reform',163,'/avatars/273.jpg'),
(274,'hillaryclinton','lbn123456','Hillary Clinton','Democrat','Liberal','Female','U.S. Senator from New York','Wellesley College; Yale Law School','J.D.','New York','Hillary Rodham Clinton (born 1947) is a Democrat who served as U.S. Senator from New York (2001–2009). Earlier she was First Lady of the United States (1993–2001) and worked as an attorney and policy advocate. After the Senate, she was U.S. Secretary of State (2009–2013) and later the 2016 Democratic presidential nominee.','Law & Justice',167,'/avatars/274.jpg'),
(275,'joncorzine','lbn123456','Jon Corzine','Democrat','Liberal','Male','U.S. Senator from New Jersey','University of Illinois Urbana-Champaign','Bachelor','New Jersey','Jon Corzine is a Democrat who served as U.S. Senator from New Jersey (2001–2006). A former Goldman Sachs executive, he entered politics after a finance career and later became New Jersey’s 54th governor (2006–2010). He lost reelection in 2009 to Chris Christie. After leaving office, he became CEO of MF Global, which collapsed in 2011.','Medicine & Health|Economics & Finance|Foreign Relations',165,'/avatars/275.svg'),
(276,'markdayton','lbn123456','Mark Dayton','Democrat','Liberal','Male','U.S. Senator from Minnesota','Yale University','Bachelor','Minnesota','Mark Dayton (born 1947) is a Minnesota Democratic–Farmer–Labor politician. He served as Minnesota state auditor (1991–1995), U.S. senator from Minnesota (2001–2007), and governor of Minnesota (2011–2019). A Yale graduate, he previously worked in teaching and social work and served as a legislative aide to Sen. Walter Mondale and Gov. Rudy Perpich.','Agriculture & Rural|Civil Rights & Society',161,'/avatars/276.svg'),
(277,'earlnelson1','lbn123456','Earl Nelson','Democrat','Moderate','Male','U.S. Senator from Wisconsin','San Jose State College','Bachelor','Wisconsin','Gaylord A. Nelson was a Democratic U.S. Senator from Wisconsin (1963–1981) and previously served as Wisconsin governor (1959–1963). In the Senate he was known for conservation and environmental legislation and is widely credited as the founder of Earth Day (first held in 1970). After leaving office, he worked on environmental issues and later received the Presidential Medal of Freedom.','Environment & Energy',160,'/avatars/277.jpg'),
(278,'deborahstabenow','lbn123456','Deborah Stabenow','Democrat','Liberal','Female','U.S. Senator from Michigan','Michigan State University','Master','Michigan','Deborah “Debbie” Stabenow (born 1950) is a Michigan Democrat who served as a U.S. senator from 2001 to 2025, Michigan’s first female senator. She previously represented Michigan’s 8th district in the U.S. House (1997–2001) and served in Michigan state and local government. In the Senate she chaired the Agriculture Committee (2011–2015, 2021–2025) and led the Senate Democratic Policy Committee.','Agriculture & Rural|Governance & Reform',159,'/avatars/278.jpg'),
(279,'johnensign','lbn123456','John Ensign','Republican','Conservative','Male','U.S. Senator from Nevada','Oregon State University; Colorado State University','D.V.M.','Nevada','John E. Ensign is a Republican former U.S. Senator from Nevada (2001–2011). Previously, he represented Nevada’s 1st congressional district in the U.S. House (1995–1999). A veterinarian by training, he earned degrees from Oregon State University and a D.V.M. from Colorado State University. He resigned from the Senate in 2011 amid a Senate Ethics Committee investigation related to an extramarital affair.','Education & Science|Governance & Reform',166,'/avatars/279.jpg'),
(280,'mariacantwell','lbn123456','Maria Cantwell','Democrat','Liberal','Female','U.S. Senator from Washington','Miami University','Bachelor','Washington','Maria Cantwell (born 1958) is a Washington Democrat serving as a U.S. senator since 2001. She previously served in the Washington House of Representatives (1987–1993) and one term in the U.S. House representing Washington’s 1st district (1993–1995). After working at RealNetworks, she returned to politics and narrowly defeated Republican Sen. Slade Gorton in 2000.','Governance & Reform',169,'/avatars/280.svg'),
(281,'georgeallen1','lbn123456','George Allen','Republican','Conservative','Male','U.S. Senator from Virginia','University of Virginia','J.D.','Virginia','George F. Allen (born 1952) is a Virginia Republican politician and lawyer. He served in the Virginia House of Delegates (1983–1991), then as U.S. Representative for Virginia''s 7th district (1991–1993). He was Governor of Virginia (1994–1998) and later U.S. Senator from Virginia (2001–2007), after defeating Sen. Chuck Robb in 2000.','Law & Justice',168,'/avatars/281.svg'),
(282,'earlnelson2','lbn123456','Earl Nelson','Democrat','Moderate','Male','U.S. Senator from Nebraska','University of Nebraska–Lincoln; University of Nebraska College of Law','J.D.','Nebraska','E. Benjamin "Ben" Nelson (born 1941) is a Nebraska politician, attorney, and former insurance executive. A Democrat, he served as governor of Nebraska (1991–1999), then as U.S. senator from Nebraska (2001–2013). He lost a 1996 Senate race to Chuck Hagel, won election in 2000, and was reelected in 2006. After leaving the Senate, he worked in business and advocacy roles.','Law & Justice',160,'/avatars/282.svg'),
(283,'deanmbarkley','lbn123456','Dean M. Barkley','Independence Party (Minnesota) (formerly Reform Party)','Centrist','Male','U.S. Senator from Minnesota','University of Minnesota','J.D.','Minnesota','Dean M. Barkley (born 1950) is a Minnesota attorney and politician. Founder and chair of the Minnesota Reform Party (later Independence Party), he managed Jesse Ventura’s 1998 gubernatorial campaign and later served in Ventura’s administration. After Sen. Paul Wellstone’s death, Ventura appointed Barkley to the U.S. Senate, where he served from 2002 to 2003 until Republican Norm Coleman took office.','Governance & Reform|Law & Justice',NULL,'/avatars/283.svg'),
(284,'davidpryor1','lbn123456','David Pryor','Democrat','Moderate','Male','U.S. Senator from Arkansas','University of Arkansas','J.D.','Arkansas','Mark Lunsford Pryor (born 1963) is an Arkansas attorney and Democrat. He served in the Arkansas House of Representatives (1991–1995), was Arkansas Attorney General (1999–2003), and represented Arkansas in the U.S. Senate (2003–2015). The son of former Governor and U.S. Senator David Pryor, he lost reelection in 2014 to Tom Cotton and later worked as a lobbyist.','Law & Justice',2,'/avatars/284.jpg'),
(285,'bobgraham1','lbn123456','Bob Graham','Republican','Conservative','Male','U.S. Senator from South Carolina','University of South Carolina','J.D.','South Carolina','Lindsey Olin Graham (born 1955) is a Republican U.S. senator from South Carolina, serving since 2003. He previously represented South Carolina''s 3rd district in the U.S. House (1995–2003) and served in the South Carolina House (1993–1995). An attorney, he served in the U.S. Air Force JAG Corps and later the Air Force Reserve, reaching colonel. He chaired the Senate Judiciary Committee (2019–2021).','Law & Justice',50,'/avatars/285.jpg'),
(286,'saxbychambliss','lbn123456','Saxby Chambliss','Republican','Conservative','Male','U.S. Senator from Georgia','University of Georgia; University of Tennessee','J.D.','Georgia','Saxby Chambliss (born 1943) is a Republican lawyer and retired politician from Georgia. He served in the U.S. House of Representatives for Georgia’s 8th district (1995–2003), including chairing the House Intelligence Subcommittee on Terrorism and Homeland Security. Elected to the U.S. Senate in 2002, he represented Georgia from 2003 to 2015 and chaired the Senate Agriculture Committee (2005–2007).','Defense & Security|Law & Justice|Agriculture & Rural',171,'/avatars/286.jpg'),
(287,'normcoleman','lbn123456','Norm Coleman','Democratic–Farmer–Labor (DFL) (until 1996), Republican (1996-2009)','Conservative','Male','U.S. Senator from Minnesota','Hofstra University; Brooklyn Law School','J.D.','Minnesota','Norm Coleman (born 1949) is a Minnesota politician and attorney. Originally elected as a Democratic–Farmer–Labor member, he switched to the Republican Party in 1996. He served as mayor of Saint Paul (1994–2002) and then as U.S. senator from Minnesota (2003–2009). He won the Senate seat in 2002 and lost a closely contested reelection bid in 2008.','Law & Justice|Agriculture & Rural|Civil Rights & Society',172,'/avatars/287.jpg'),
(288,'lamaralexander','lbn123456','Lamar Alexander','Republican','Conservative','Male','U.S. Senator from Tennessee','Vanderbilt University; New York University School of Law','J.D.','Tennessee','Lamar Alexander (born 1940) is a Tennessee Republican who served as U.S. senator from 2003 to 2021. He previously was governor of Tennessee (1979–1987) and U.S. secretary of education (1991–1993) under President George H. W. Bush. An attorney and academic administrator, he supported education reform initiatives and later held Senate leadership and committee roles.','Education & Science|Law & Justice|Governance & Reform',179,'/avatars/288.jpg'),
(289,'johncornyn','lbn123456','John Cornyn','Republican','Conservative','Male','U.S. Senator from Texas','Trinity University; St. Mary''s University School of Law; University of Virginia School of Law','J.D.','Texas','John Cornyn III is a Republican U.S. Senator from Texas, first elected in 2002. Born in Houston, he previously served as a Texas district judge (1985–1991), justice of the Texas Supreme Court (1991–1997), and Texas Attorney General (1999–2002). In the Senate he chaired the National Republican Senatorial Committee (2009–2013) and served as Senate Republican whip (2013–2019).','Law & Justice',176,'/avatars/289.svg'),
(290,'robertdole1','lbn123456','Robert Dole','Republican','Conservative','Female','U.S. Senator from North Carolina','Duke University; Harvard Law School','J.D.','North Carolina','Elizabeth H. Dole is a Republican politician and attorney who served as U.S. Senator from North Carolina (2003–2009). She previously held senior executive-branch roles, including U.S. Secretary of Transportation under Ronald Reagan (1983–1987) and U.S. Secretary of Labor under George H. W. Bush (1989–1990). She was president of the American Red Cross (1991–1999) and sought the 2000 Republican presidential nomination.','Law & Justice|Civil Rights & Society',12,'/avatars/290.svg'),
(291,'johnsununu','lbn123456','John Sununu','Republican','Conservative','Male','U.S. Senator from New Hampshire','Massachusetts Institute of Technology; Harvard University','Master','New Hampshire','John E. Sununu (born 1964) is a Republican politician from New Hampshire. He served as U.S. Representative for New Hampshire’s 1st district (1997–2003) and then as U.S. Senator from New Hampshire (2003–2009), noted as the Senate’s youngest member throughout his term. He lost reelection in 2008 to Democrat Jeanne Shaheen. He is the son of former New Hampshire governor and White House chief of staff John H. Sununu.','Governance & Reform',178,'/avatars/291.svg'),
(292,'jamestalent','lbn123456','James Talent','Republican','Conservative','Male','U.S. Senator from Missouri','Washington University in St. Louis; University of Chicago','J.D.','Missouri','James "Jim" Talent (born 1956) is a Republican politician from Missouri. He served in the U.S. House representing Missouri’s 2nd district (1993–2001), then won a 2002 special election for the U.S. Senate, serving from 2002 to 2007. He lost reelection in 2006 to Claire McCaskill. After office he worked as a policy adviser, including with Mitt Romney, and at the Heritage Foundation.','Governance & Reform',173,'/avatars/292.svg'),
(293,'frankmurkowski1','lbn123456','Frank Murkowski','Republican','Moderate','Female','U.S. Senator from Alaska','Georgetown University; Willamette University','J.D.','Alaska','Lisa Murkowski (born 1957) is a Republican U.S. senator from Alaska, first appointed in 2002 to fill the seat vacated by her father, Gov. Frank Murkowski. Previously she served in the Alaska House of Representatives (1999–2002). She won election to a full Senate term in 2004 and has since been reelected, often as a pragmatic, centrist-leaning Republican.','Governance & Reform',90,'/avatars/293.jpg'),
(294,'thomascarper','lbn123456','Thomas Carper','Democrat','Moderate','Male','U.S. Senator from Delaware','Ohio State University; University of Delaware','Master','Delaware','Tom Carper is a Democratic politician from Delaware. A former U.S. Navy officer, he served as Delaware state treasurer (1977–1983), U.S. representative (1983–1993), and governor of Delaware (1993–2001). He was elected to the U.S. Senate in 2000 and served from 2001 to 2025, focusing on fiscal issues, transportation, and environmental policy.','Defense & Security|Law & Justice|Economics & Finance',164,'/avatars/294.svg');
